window.PACTO.acts["reg-2016-399"]={"label": "REGOLAMENTO (UE) 2016/399 DEL PARLAMENTO EUROPEO E DEL CONSIGLIO", "short": "Reg. 2016/399", "file": "ext-reg-2016-399.html", "external": true, "version": "consolidato 2025-10-12", "eurlex": "https://eur-lex.europa.eu/eli/reg/2016/399/oj/ita", "articles": {"1": {"label": "Articolo 1", "heading": "Oggetto e principi", "anchor": "art_1", "frags": [[null, "<p class=\"norm\">Il presente regolamento prevede l’assenza del controllo di frontiera sulle persone che attraversano le frontiere interne tra gli Stati membri dell’Unione.</p>"], [null, "<p class=\"norm\">Esso stabilisce le norme applicabili al controllo di frontiera sulle persone che attraversano le frontiere esterne degli Stati membri dell’Unione.</p>"]]}, "2": {"label": "Articolo 2", "heading": "Definizioni", "anchor": "art_2", "frags": [[null, "<p class=\"norm\">Ai fini del presente regolamento, si intende per:</p>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">1)</p>\n</td>\n<td valign=\"top\">\n<p class=\"normal\">«frontiere interne»</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le frontiere terrestri comuni, comprese le frontiere fluviali e lacustri, degli Stati membri;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli aeroporti degli Stati membri adibiti ai voli interni;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i porti marittimi, fluviali e lacustri degli Stati membri per i collegamenti regolari interni effettuati da traghetti;</p>\n</div>\n</div>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">2)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«frontiere esterne»le frontiere terrestri, comprese quelle fluviali e lacustri, le frontiere marittime e gli aeroporti, i porti fluviali, marittimi e lacustri degli Stati membri, che non siano frontiere interne;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">3)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«volo interno»qualunque volo in provenienza esclusiva dai territori degli Stati membri o con destinazione esclusiva verso di essi, senza atterraggio sul territorio di un paese terzo;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">4)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«collegamento regolare interno effettuato da traghetto»qualunque collegamento effettuato da traghetto tra gli stessi due o più porti situati sul territorio degli Stati membri, senza scalo in porti situati al di fuori di tali territori e comportante il trasporto di persone e veicoli in base ad un orario pubblicato;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">5)</p>\n</td>\n<td valign=\"top\">\n<p class=\"normal\">«beneficiari del diritto alla libera circolazione ai sensi del diritto unionale»</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i cittadini dell’Unione ai sensi dell’ articolo 20, paragrafo 1, TFUE, nonché i cittadini di paesi terzi familiari di un cittadino dell’Unione che esercita il suo diritto alla libera circolazione sul territorio dell’Unione europea, ai quali si applica la direttiva 2004/38/CE del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">1</span>\n);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i cittadini di paesi terzi e i loro familiari, qualunque sia la loro nazionalità, che, in virtù di accordi conclusi tra l'Unione e i suoi Stati membri, da un lato, e tali paesi terzi, dall’altro, beneficiano di diritti in materia di libera circolazione equivalenti a quelli dei cittadini dell’Unione;</p>\n</div>\n</div>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">6)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«cittadino di paese terzo»chi non è cittadino dell’Unione ai sensi dell’ articolo 20, paragrafo 1, TFUE e non è contemplato dal punto 5 del presente articolo;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">7)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«persona segnalata ai fini della non ammissione»qualsiasi cittadino di paese terzo segnalato nel sistema d’informazione Schengen (SIS) ai sensi e per gli effetti dell’articolo 24 e 26 del regolamento (CE) n. 1987/2006 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">2</span>\n);</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">8)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«valico di frontiera»ogni valico autorizzato dalle autorità competenti per il passaggio delle frontiere esterne;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">9)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«valico di frontiera condiviso»qualsiasi valico di frontiera situato sul territorio di uno Stato membro o su quello di un paese terzo, in cui guardie di frontiera dello Stato membro e guardie di frontiera del paese terzo effettuano verifiche in uscita e in entrata gli uni dopo gli altri conformemente al relativo diritto nazionale e ai sensi di un accordo bilaterale;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">10)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«controllo di frontiera»l’attività svolta alla frontiera, in conformità e per gli effetti del presente regolamento, in risposta esclusivamente all’intenzione di attraversare la frontiera o al suo effettivo attraversamento e indipendentemente da qualunque altra ragione, e che consiste in verifiche di frontiera e nella sorveglianza di frontiera;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">11)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«verifiche di frontiera»le verifiche effettuate ai valichi di frontiera al fine di accertare che le persone, compresi i loro mezzi di trasporto e gli oggetti in loro possesso, possano essere autorizzati ad entrare nel territorio degli Stati membri o autorizzati a lasciarlo;</p>\n</td>\n</tr>\n</table>"], [null, "<p class=\"modref\">\n▼M7\n</p>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">12)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«sorveglianza di frontiera»la sorveglianza delle frontiere tra valichi di frontiera e la sorveglianza dei valichi di frontiera al di fuori degli orari di apertura stabiliti, comprese le misure preventive, per impedire o individuare l’attraversamento non autorizzato della frontiera o che siano eluse le verifiche di frontiera, contribuire ad accrescere la conoscenza situazionale, contrastare la criminalità transfrontaliera e adottare misure contro le persone entrate illegalmente;</p>\n</td>\n</tr>\n</table>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">13)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«verifica in seconda linea»una verifica supplementare che può essere effettuata in un luogo specifico, diverso da quello in cui sono effettuate le verifiche su tutte le persone (prima linea);</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">14)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«guardia di frontiera»il pubblico ufficiale assegnato, conformemente alla legislazione nazionale, ad un valico di frontiera oppure lungo la frontiera o nelle immediate vicinanze di quest’ultima, che assolve, in conformità del presente regolamento e della legislazione nazionale, compiti di controllo di frontiera;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">15)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«vettore»;ogni persona fisica o giuridica che trasporta persone a titolo professionale</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">16)</p>\n</td>\n<td valign=\"top\">\n<p class=\"normal\">«permesso di soggiorno»:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">tutti i permessi di soggiorno rilasciati dagli Stati membri secondo il modello uniforme istituito dal regolamento (CE) n. 1030/2002 del Consiglio (\n<span class=\"superscript\">3</span>\n), e le carte di soggiorno rilasciate conformemente alla direttiva 2004/38/CE;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">qualsiasi altro documento rilasciato da uno Stato membro a cittadini di paesi terzi che autorizzi questi ultimi a soggiornare sul suo territorio, che sia stato oggetto di una comunicazione e di una successiva pubblicazione ai sensi dell'articolo 39, a eccezione:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dei permessi temporanei rilasciati in attesa dell’esame di una prima domanda di permesso di soggiorno ai sensi della lettera a) o di una domanda d’asilo, e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dei visti rilasciati dagli Stati membri secondo il modello uniforme di cui al regolamento (CE) n. 1683/95 del Consiglio (\n<span class=\"superscript\">4</span>\n).</p>\n</div>\n</div>\n</div>\n</div>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">17)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«nave da crociera»una nave che effettua un viaggio secondo un programma prestabilito, che comprende un programma di escursioni turistiche nei vari porti e durante il quale di norma non vi è né imbarco né sbarco di passeggeri;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">18)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«navigazione da diporto»l’uso di imbarcazioni da diporto a fini sportivi o turistici;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">19)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«pesca costiera»le attività di pesca effettuate mediante navi che rientrano quotidianamente o entro 36 ore in un porto situato nel territorio degli Stati membri senza fare scalo in un porto situato in un paese terzo;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">20)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«lavoratore offshore»una persona che svolge la propria attività su un'installazione offshore situata nelle acque territoriali degli Stati membri o in una loro zona di sfruttamento economico esclusivo delle risorse marine, quale definita dal diritto marittimo internazionale, e che torna periodicamente per via marittima o aerea nel territorio degli Stati membri;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">21)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«minaccia per la salute pubblica»qualunque malattia con potenziale epidemico ai sensi del regolamento sanitario internazionale dell’Organizzazione mondiale della sanità e altre malattie infettive o parassitarie contagiose che siano oggetto di disposizioni di protezione applicabili ai cittadini degli Stati membri;</p>\n</td>\n</tr>\n</table>"], [null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">22)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«sistema di ingressi/uscite»(Entry/Exit System - EES) il sistema istituito con regolamento (UE) 2017/2226 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">5</span>\n);</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">23)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«sistema self-service»un sistema automatizzato che effettua tutte le verifiche di frontiera applicabili a una persona, o una parte di esse, e che può essere utilizzato per il preinserimento dei dati nell’EES;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">24)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«varco automatico»un’infrastruttura elettronica in cui una frontiera esterna o una frontiera interna presso cui i controlli non sono ancora stati eliminati è effettivamente attraversata;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">25)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«sistema di controllo di frontiera automatizzato»un sistema che consente l’attraversamento automatizzato della frontiera, e che si compone di un sistema self-service e di un varco automatico;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">26)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«conferma dell’autenticità e dell’integrità dei dati memorizzati nel chip»il processo con cui si verifica, mediante certificati, che i dati memorizzati nel supporto di memorizzazione elettronica (chip) provengano dall’autorità emittente e non siano stati modificati;</p>\n</td>\n</tr>\n</table>"], [null, "<p class=\"modref\">\n▼M7\n</p>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">27)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«emergenza di sanità pubblica su vasta scala»un’emergenza di sanità pubblica, riconosciuta a livello di Unione dalla Commissione, tenuto conto delle informazioni fornite dalle autorità nazionali competenti, in cui una grave minaccia per la salute a carattere transfrontaliero potrebbe avere ripercussioni su vasta scala sull’esercizio del diritto alla libera circolazione;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">28)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«viaggi essenziali»i viaggi di una persona esentata da restrizioni all’ingresso a norma dell’articolo 21 <span class=\"italics\">bis</span>, paragrafo 4 o 5, dettati da funzioni o necessità essenziali, tenuto conto degli obblighi internazionali dell’Unione e degli Stati membri applicabili;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">29)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«viaggi non essenziali»i viaggi dettati da finalità diverse dai viaggi essenziali;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">30)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«poli di trasporto»aeroporti, porti marittimi o fluviali, stazioni ferroviarie o autostazioni come anche terminali merci.</p>\n</td>\n</tr>\n</table>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "3": {"label": "Articolo 3", "heading": "Campo di applicazione", "anchor": "art_3", "frags": [[null, "<p class=\"norm\">Il presente regolamento si applica a chiunque attraversi le frontiere interne o esterne di uno Stato membro, senza pregiudizio:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dei diritti dei beneficiari del diritto alla libera circolazione ai sensi del diritto unionale;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dei diritti dei rifugiati e di coloro che richiedono protezione internazionale, in particolare per quanto concerne il non respingimento.</p>\n</div>\n</div>"]]}, "4": {"label": "Articolo 4", "heading": "Diritti fondamentali", "anchor": "art_4", "frags": [[null, "<p class=\"norm\">In sede di applicazione del presente regolamento, gli Stati membri agiscono nel pieno rispetto del pertinente diritto unionale, compresa la Carta dei diritti fondamentali dell'Unione europea («Carta»), del pertinente diritto internazionale, compresa la convenzione relativa allo status dei rifugiati firmata a Ginevra il 28 luglio 1951 («convenzione di Ginevra»), degli obblighi inerenti all'accesso alla protezione internazionale, in particolare il principio di <span class=\"italics\">non-refoulement</span> (non respingimento), e dei diritti fondamentali. Conformemente ai principi generali del diritto unionale, le decisioni adottate ai sensi del presente regolamento devono essere adottate su base individuale.</p>"]]}, "5": {"label": "Articolo 5", "heading": "Attraversamento delle frontiere esterne", "anchor": "art_5", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le frontiere esterne possono essere attraversate soltanto ai valichi di frontiera e durante gli orari di apertura stabiliti. Ai valichi di frontiera che non sono aperti 24 ore al giorno gli orari di apertura devono essere indicati chiaramente.</div>\n</div>"], [null, "<p class=\"norm\">Gli Stati membri notificano l’elenco dei loro valichi di frontiera alla Commissione a norma dell’articolo 39.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">In deroga al paragrafo 1, possono essere previste eccezioni all’obbligo di attraversare le frontiere esterne ai valichi di frontiera e durante gli orari di apertura:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per persone o gruppi di persone, in presenza di una necessità di carattere particolare di attraversamento occasionale delle frontiere esterne al di fuori dei valichi di frontiera o al di fuori degli orari di apertura stabiliti, purché siano in possesso delle autorizzazioni richieste dal diritto nazionale e purché non ostino ragioni di ordine pubblico e di sicurezza interna degli Stati membri. Gli Stati membri possono stabilire regimi specifici in accordi bilaterali. Le eccezioni generali previste dal diritto nazionale e dagli accordi bilaterali sono comunicate alla Commissione a norma dell'articolo 39;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per persone o gruppi di persone in caso di un’imprevista situazione d’emergenza;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">conformemente alle norme specifiche di cui agli articoli 19 e 20 in combinato disposto con gli allegati VI e VII.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Fatte salve le eccezioni di cui al paragrafo 2 o i loro obblighi in materia di protezione internazionale, gli Stati membri impongono sanzioni, a norma della legislazione nazionale, in caso di attraversamento non autorizzato delle frontiere esterne al di fuori dei valichi di frontiera e degli orari di apertura stabiliti. Tali sanzioni sono effettive, proporzionate e dissuasive.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M7\n</p>"], [null, "<p class=\"norm\">Qualora un gran numero di migranti cerchi di attraversare le loro frontiere esterne in modo non autorizzato, in massa e usando la forza, gli Stati membri possono adottare le misure necessarie per preservare la sicurezza e l’ordine pubblico.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">In particolare in una situazione di strumentalizzazione dei migranti di cui all’articolo 1, paragrafo 4, lettera b), prima frase, del regolamento (UE) 2024/1359 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">6</span>\n), gli Stati membri possono chiudere temporaneamente specifici valichi di frontiera notificati a norma del paragrafo 1, secondo comma, o limitarne gli orari di apertura, ove le circostanze lo richiedano.</div>\n</div>"], [null, "<p class=\"norm inline-element\">Le misure di cui al primo comma del presente paragrafo e al paragrafo 3, secondo comma, del presente articolo sono attuate in modo proporzionato e tengono pienamente conto dei diritti:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dei beneficiari del diritto alla libera circolazione ai sensi del diritto dell’Unione;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dei cittadini di paesi terzi che siano soggiornanti di lungo periodo a norma della direttiva 2003/109/CE del Consiglio (\n<span class=\"superscript\">7</span>\n) e persone che beneficiano del diritto di soggiorno in virtù di altri strumenti del diritto dell’UE o nazionale, o che siano in possesso di un visto nazionale per soggiorno di lunga durata, nonché i loro familiari; e</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dei cittadini di paesi terzi che chiedono protezione internazionale.</p>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "6": {"label": "Articolo 6", "heading": "Condizioni d’ingresso per i cittadini di paesi terzi", "anchor": "art_6", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Per soggiorni previsti nel territorio degli Stati membri, la cui durata non sia superiore a 90 giorni su un periodo di 180 giorni, il che comporta di prendere in considerazione il periodo di 180 giorni che precede ogni giorno di soggiorno, le condizioni d'ingresso per i cittadini di paesi terzi sono le seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">essere in possesso di un documento di viaggio valido che autorizza il titolare ad attraversare la frontiera che soddisfi i seguenti criteri:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la validità è di almeno tre mesi dopo la data prevista per la partenza dal territorio degli Stati membri. In casi di emergenza giustificati, è possibile derogare a tale obbligo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è stato rilasciato nel corso dei dieci anni precedenti;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">essere in possesso di un visto valido, se richiesto a norma del regolamento (CE) n. 539/2001 del Consiglio (\n<span class=\"superscript\">8</span>\n), salvo che si sia in possesso di un permesso di soggiorno o di un visto per soggiorni di lunga durata in corso di validità;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">giustificare lo scopo e le condizioni del soggiorno previsto e disporre dei mezzi di sussistenza sufficienti, sia per la durata prevista del soggiorno sia per il ritorno nel paese di origine o per il transito verso un paese terzo nel quale l’ammissione è garantita, ovvero essere in grado di ottenere legalmente detti mezzi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">non essere segnalato nel SIS ai fini della non ammissione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">non essere considerato una minaccia per l’ordine pubblico, la sicurezza interna, la salute pubblica o le relazioni internazionali di uno degli Stati membri, in particolare non essere oggetto di segnalazione ai fini della non ammissione nelle banche dati nazionali degli Stati membri per gli stessi motivi;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M3\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">fornire dati biometrici, laddove richiesti per:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la costituzione del fascicolo individuale nell’EES conformemente agli articoli 16 e 17 del regolamento (UE) 2017/2226;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’effettuazione di verifiche di frontiera a norma dell’articolo 8, paragrafo 3, lettera a), punto i), e lettera g), punto i), del presente regolamento, dell’articolo 23, paragrafi 2 e 4, del regolamento (UE) 2017/2226 e, se del caso, dell’articolo 18 del regolamento (CE) n. 767/2008 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">9</span>\n).</p>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1 <span class=\"italics\">bis</span>.  </span>\n<div class=\"norm inline-element\">Il periodo di 90 giorni su un periodo di 180 giorni di cui al paragrafo 1 del presente articolo è calcolato come periodo unico per gli Stati membri in cui l’EES è operativo sulla base del regolamento (UE) 2017/2226. Tale periodo è calcolato separatamente per ciascuno degli Stati membri in cui l’EES non è operativo.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Ai fini dell'applicazione del paragrafo 1, la data d'ingresso è considerata come il primo giorno di soggiorno sul territorio degli Stati membri e la data d'uscita è considerata come l'ultimo giorno di soggiorno sul territorio degli Stati membri. I periodi di soggiorno autorizzati nell'ambito di un permesso di soggiorno o di un visto per soggiorno di lunga durata o di un permesso di soggiorno non sono presi in considerazione nel calcolo della durata di un soggiorno nel territorio degli Stati membri.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">L’allegato I comprende un elenco non esauriente dei giustificativi che le guardie di frontiera possono chiedere ai cittadini di paesi terzi al fine di verificare il rispetto delle condizioni previste al paragrafo 1, lettera c).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La valutazione dei mezzi di sussistenza si effettua in funzione della durata e dello scopo del soggiorno e con riferimento ai prezzi medi vigenti nello o negli Stati membri interessati di vitto e alloggio in sistemazione economica, moltiplicati per il numero di giorni del soggiorno.</div>\n</div>"], [null, "<p class=\"norm\">Gli importi di riferimento fissati dagli Stati membri sono notificati alla Commissione a norma dell’articolo 39.</p>"], [null, "<p class=\"norm\">La valutazione della disponibilità di mezzi di sussistenza sufficienti può basarsi sul possesso di contanti, assegni turistici e carte di credito da parte del cittadino di paese terzo. Le dichiarazioni di presa a carico, qualora siano previste dalle legislazioni nazionali, e, nel caso di cittadini di paesi terzi che vengano ospitati, le lettere di garanzia delle persone ospitanti, quali definite dalle legislazioni nazionali, possono altresì costituire una prova della disponibilità di mezzi di sussistenza sufficienti.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">In deroga al paragrafo 1:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i cittadini di paesi terzi che non soddisfano tutte le condizioni di cui al paragrafo 1, ma che sono in possesso di un permesso di soggiorno o di un visto per soggiorno di lunga durata, sono ammessi a entrare nel territorio degli altri Stati membri ai fini di transito, affinché possano raggiungere il territorio dello Stato membro che ha rilasciato il permesso di soggiorno o il visto per soggiorno di lunga durata, a meno che non figurino nell’elenco nazionale delle persone segnalate dallo Stato membro alle cui frontiere esterne essi si presentano e che tale segnalazione sia accompagnata da istruzioni di respingere o rifiutare il transito;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i cittadini di paesi terzi che soddisfano le condizioni di cui al paragrafo 1, salvo la lettera b), e che si presentano alla frontiera possono essere ammessi nel territorio degli Stati membri se è stato loro rilasciato un visto alla frontiera a norma degli articoli 35 e 36 del regolamento (CE) n. 810/2009 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">10</span>\n).</p>\n<p class=\"list\">Gli Stati membri compilano statistiche sui visti rilasciati alle frontiere conformemente all'articolo 46 del regolamento (CE) n. 810/2009 e al relativo allegato XII.</p>\n<p class=\"list\">Se non è possibile apporre un visto sul documento, esso è apposto, in via eccezionale, su un foglio separato inserito nel documento. In tal caso viene utilizzato il modello uniforme di foglio per l’apposizione di un visto istituito dal regolamento (CE) n. 333/2002 del Consiglio (\n<span class=\"superscript\">11</span>\n);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i cittadini di paesi terzi che non soddisfano una o più delle condizioni di cui al paragrafo 1 possono essere autorizzati da uno Stato membro ad entrare nel suo territorio per motivi umanitari o di interesse nazionale o in virtù di obblighi internazionali. Qualora il cittadino di paese terzo interessato sia oggetto di una segnalazione di cui al paragrafo 1, lettera d), lo Stato membro che ne autorizza l’ingresso nel suo territorio ne informa gli altri Stati membri.</p>\n</div>\n</div>\n</div>\n</div>"]]}, "6a": {"label": "Articolo 6 bis", "heading": "Cittadini di paesi terzi i cui dati devono essere inseriti nell’EES", "anchor": "art_6a", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">I dati all’ ingresso e all’uscita delle seguenti categorie di persone sono inseriti nell’EES conformemente agli articoli 16, 17, 19 e 20 del regolamento (UE) 2017/2226:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">cittadini di paesi terzi ammessi per un soggiorno di breve durata ai sensi dell’articolo 6, paragrafo 1, del presente regolamento;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">cittadini di paesi terzi familiari di un cittadino dell’Unione ai quali si applica la direttiva 2004/38/CE e che non sono in possesso della carta di soggiorno di cui a tale direttiva;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">cittadini di paesi terzi che:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sono familiari di un cittadino di paese terzo beneficiario del diritto alla libera circolazione equivalente a quello dei cittadini dell’Unione in virtù di un accordo concluso tra l’Unione e i suoi Stati membri, da una parte, e un paese terzo, dall’altra; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">non sono in possesso della carta di soggiorno a norma della direttiva 2004/38/CE o di un permesso di soggiorno conformemente al regolamento (CE) n. 1030/2002.</p>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I dati relativi ai cittadini di paesi terzi a cui è stato rifiutato l’ingresso per un soggiorno di breve durata ai sensi dell’articolo 14 del presente regolamento sono inseriti nell’EES conformemente all’articolo 18 del regolamento (UE) 2017/2226.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Non sono inseriti nell’EES i dati delle seguenti categorie di persone:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">cittadini di paesi terzi familiari di un cittadino dell’Unione ai quali si applica la direttiva 2004/38/CE e che sono in possesso della carta di soggiorno a norma di tale direttiva che accompagnino o raggiungano, o meno, tale cittadino dell’Unione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">cittadini di paesi terzi che sono familiari di un cittadino di paese terzo, che accompagnino o raggiungano, o meno, tale cittadino dell’Unione, qualora:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">tale cittadino di paese terzo benefici di un diritto alla libera circolazione equivalente a quello dei cittadini dell’Unione in virtù di un accordo concluso tra l’Unione e i suoi Stati membri, da una parte, e un paese terzo, dall’altra; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">tali cittadini di paesi terzi siano in possesso della carta di soggiorno a norma della direttiva 2004/38/CE o di un permesso di soggiorno conformemente al regolamento (CE) n. 1030/2002;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">titolari di permessi di soggiorno di cui all’articolo 2, punto 16, ad eccezione di coloro che sono contemplati alle precedenti lettere a) e b);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">titolari di visti per soggiorni di lunga durata;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">cittadini di paesi terzi che esercitano i loro diritti alla mobilità ai sensi della direttiva 2014/66/UE del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">*1</span>\n) o della direttiva (UE) 2016/801 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">*2</span>\n);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">cittadini di Andorra, Monaco e San Marino <span>\n<span class=\"boldface\">►C1</span>\n</span> e titolari di un passaporto rilasciato dallo Stato della Città del Vaticano o Santa Sede;<span class=\"boldface\"> ◄ </span>\n</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">persone o categorie di persone esenti dalle verifiche di frontiera o che beneficiano di specifiche norme relative alle verifiche di frontiera, vale a dire:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">capi di Stato, capi di governo e membri dei governi nazionali, accompagnati dai consorti, e membri delle loro delegazioni ufficiali, e sovrani e altri membri di rilievo di una famiglia reale, ai sensi del punto 1 dell’allegato VII;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">piloti di aeromobili e altri membri dell’equipaggio ai sensi del punto 2 dell’allegato VII;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">marittimi ai sensi del punto 3 dell’allegato VII e marittimi presenti all’interno del territorio di uno Stato membro soltanto per la durata dello scalo della nave e nella zona del porto di scalo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iv) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">lavoratori frontalieri ai sensi del punto 5 dell’allegato VII;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>v) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">servizi di soccorso, polizia, vigili del fuoco che intervengono in una situazione d’emergenza e guardie di frontiera ai sensi del punto 7 dell’allegato VII;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>vi) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">lavoratori off-shore ai sensi del punto 8 dell’allegato VII;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>vii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">membri dell’equipaggio e passeggeri di navi da crociera ai sensi dei punti 3.2.1, 3.2.2 e 3.2.3 dell’allegato VI;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>viii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">persone che si trovano a bordo di un’imbarcazione da diporto che non sono soggette alle verifiche di frontiera ai sensi dei punti 3.2.4, 3.2.5 e 3.2.6 dell’allegato VI;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">persone che beneficiano di una deroga all’obbligo di attraversare le frontiere esterne soltanto ai valichi di frontiera e durante gli orari di apertura stabiliti ai sensi dell’articolo 5, paragrafo 2;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">persone che, per l’attraversamento della frontiera, presentano un valido lasciapassare per traffico frontaliero in conformità del regolamento (CE) n. 1931/2006 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">*3</span>\n);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>j) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">membri dell’equipaggio di treni passeggeri e treni merci che effettuano collegamenti internazionali;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>k) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">persone che, per l’attraversamento della frontiera, presentano:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un documento di transito ferroviario agevolato rilasciato a norma del regolamento (CE) n. 693/2003 del Consiglio (\n<span class=\"superscript\">*4</span>\n); o</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un documento di transito agevolato valido rilasciato a norma del regolamento (CE) n. 693/2003, a condizione che transitino via treno e che non scendano sul territorio di uno Stato membro.</p>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>"]]}, "7": {"label": "Articolo 7", "heading": "Effettuazione delle verifiche di frontiera", "anchor": "art_7", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le guardie di frontiera esercitano le loro funzioni nel pieno rispetto della dignità umana, in particolare nei casi concernenti persone vulnerabili.</div>\n</div>"], [null, "<p class=\"norm\">Tutte le misure adottate nell’esercizio delle loro funzioni sono proporzionate agli obiettivi perseguiti con tali misure.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Nell’effettuare le verifiche di frontiera, le guardie di frontiera non esercitano verso le persone discriminazioni fondate sul sesso, la razza o l’origine etnica, la religione o le convinzioni, la disabilità, l’età o l’orientamento sessuale.</div>\n</div>"]]}, "8": {"label": "Articolo 8", "heading": "Verifiche di frontiera sulle persone", "anchor": "art_8", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L’attraversamento delle frontiere esterne è oggetto di verifiche da parte delle guardie di frontiera. Le verifiche sono effettuate a norma del presente capo.</div>\n</div>"], [null, "<p class=\"norm\">Le verifiche possono riguardare anche i mezzi di trasporto e gli oggetti di cui sono in possesso le persone che attraversano la frontiera. In caso di perquisizione si applica la legislazione dello Stato membro interessato.</p>"], [null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">All’ingresso e all’uscita, i beneficiari del diritto alla libera circolazione ai sensi del diritto dell’Unione sono sottoposti alle seguenti verifiche:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’accertamento dell’identità e della cittadinanza della persona nonché dell’autenticità e della validità del documento di viaggio per l’attraversamento della frontiera, anche tramite consultazione delle pertinenti banche dati, in particolare:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>1) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il SIS;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>2) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la banca dati dell’Interpol sui documenti di viaggio rubati e smarriti (SLTD);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>3) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le banche dati nazionali contenenti informazioni sui documenti di viaggio rubati, altrimenti sottratti, smarriti e invalidati.</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M3\n</p>\n<p class=\"list\">Se il documento di viaggio contiene un supporto di memorizzazione elettronica (chip), l’autenticità e l’integrità dei dati ivi memorizzati sono confermate ricorrendo alla catena completa di certificati validi, a meno che ciò sia tecnicamente impossibile, o, nel caso di un documento di viaggio rilasciato da un paese terzo, impossibile per indisponibilità di certificati validi.</p>\n<p class=\"modref\">\n▼M2\n</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’accertamento che il beneficiario del diritto alla libera circolazione ai sensi del diritto dell’Unione non sia considerato una minaccia per l’ordine pubblico, la sicurezza interna, la salute pubblica o le relazioni internazionali di uno degli Stati membri, anche tramite consultazione del SIS e delle altre pertinenti banche dati dell’Unione. Ciò non pregiudica la consultazione delle banche dati nazionali e dell’Interpol.</p>\n<p class=\"list\">In caso di dubbi quanto all’autenticità del documento di viaggio o all’identità del titolare, è verificato almeno uno degli identificatori biometrici integrati nei passaporti e nei documenti di viaggio rilasciati conformemente al regolamento (CE) n. 2252/2004. Ove possibile, tale accertamento è effettuato anche in relazione a documenti di viaggio non contemplati da tale regolamento.</p>\n<p class=\"modref\">\n▼M3\n</p>\n<p class=\"list\">Per le persone il cui ingresso è oggetto di registrazione nell’EES ai sensi dell’articolo 6 <span class=\"italics\">bis</span> del presente regolamento, si procede a una verifica della loro identità ai sensi dell’articolo 23, paragrafo 2, del regolamento (UE) 2017/2226 e, se del caso, a un’identificazione ai sensi dell’articolo 23, paragrafo 4, di tale regolamento.</p>\n<p class=\"modref\">\n▼M2\n</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2 <span class=\"italics\">bis</span>.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Qualora le verifiche nelle banche dati di cui al paragrafo 2, lettere a) e b), possano avere un impatto sproporzionato sul flusso di traffico, uno Stato membro può decidere di effettuare tali verifiche in modo mirato a specifici valichi di frontiera, a seguito di una valutazione dei rischi connessi con l’ordine pubblico, la sicurezza interna, la salute pubblica o le relazioni internazionali di uno degli Stati membri.</p>\n<p class=\"norm inline-element\">L’estensione e la durata della riduzione temporanea delle verifiche mirate nelle banche dati non eccedono quanto strettamente necessario e sono definite conformemente a una valutazione dei rischi effettuata dallo Stato membro interessato. La valutazione dei rischi illustra i motivi della riduzione temporanea delle verifiche mirate nelle banche dati, tiene conto, tra l’altro, dell’impatto sproporzionato sul flusso di traffico e fornisce statistiche sui passeggeri e sugli incidenti connessi alla criminalità transnazionale. Essa è regolarmente aggiornata.</p>\n<p class=\"norm inline-element\">Le persone che non sono, in linea di principio, soggette a verifiche mirate nelle banche dati, sono sottoposte, come minimo, a una verifica al fine di stabilirne l’identità dietro produzione o esibizione dei documenti di viaggio. Tale verifica consiste nel rapido e semplice accertamento della validità del documento di viaggio per l’attraversamento della frontiera, e della presenza di indizi di falsificazione o di contraffazione, se del caso servendosi di dispositivi tecnici, e, in caso di dubbi in merito al documento di viaggio o qualora vi siano indicazioni che la persona in questione potrebbe rappresentare una minaccia per l’ordine pubblico, la sicurezza interna, la salute pubblica o le relazioni internazionali degli Stati membri, la guardia di frontiera consulta le banche dati di cui al paragrafo 2, lettere a) e b).</p>\n<p class=\"norm inline-element\">Lo Stato membro interessato trasmette la propria valutazione dei rischi e i relativi aggiornamenti all’Agenzia della guardia di frontiera e costiera europea («Agenzia»), istituita dal regolamento (UE) 2016/1624 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">12</span>\n), senza indugio e riferisce ogni sei mesi alla Commissione e all’Agenzia in merito all’applicazione delle verifiche effettuate in modo mirato nelle banche dati. Lo Stato membro interessato può decidere di classificare la valutazione dei rischi, o parti di essa, come riservata.</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2 <span class=\"italics\">ter</span>.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Qualora uno Stato membro intenda effettuare verifiche mirate nelle banche dati ai sensi del paragrafo 2 <span class=\"italics\">bis</span>, lo notifica di conseguenza senza indugio agli altri Stati membri, all’Agenzia e alla Commissione. Lo Stato membro interessato può decidere di classificare la notifica, o parti di essa, come riservata.</p>\n<p class=\"norm inline-element\">Qualora gli Stati membri, l’Agenzia o la Commissione nutrano preoccupazioni sull’intenzione di effettuare verifiche mirate nelle banche dati, notificano senza indugio allo Stato membro in questione tali preoccupazioni. Lo Stato membro in questione tiene conto di tali preoccupazioni.</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2 <span class=\"italics\">quater</span>.  </span>\n<div class=\"norm inline-element\">La Commissione trasmette al Parlamento europeo e al Consiglio, entro l’8 aprile 2019, una valutazione dell’attuazione e delle conseguenze del paragrafo 2.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2 <span class=\"italics\">quinquies</span>.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Per quanto riguarda le frontiere aeree, i paragrafi 2 <span class=\"italics\">bis</span> e 2 <span class=\"italics\">ter</span> si applicano per un periodo transitorio massimo di sei mesi a decorrere dal 7 aprile 2017.</p>\n<p class=\"norm inline-element\">In casi eccezionali, qualora, in un determinato aeroporto, vi siano difficoltà infrastrutturali specifiche che richiedono un periodo di tempo più lungo per gli adeguamenti al fine di poter effettuare verifiche sistematiche nelle banche dati senza avere un impatto sproporzionato sul flusso di traffico, il periodo transitorio di sei mesi di cui al primo comma può essere prorogato per tale determinato aeroporto fino a un massimo di 18 mesi conformemente alla procedura indicata nel terzo comma.</p>\n<p class=\"norm inline-element\">A tale scopo, lo Stato membro, al più tardi tre mesi prima della scadenza del periodo transitorio di cui al primo comma, notifica alla Commissione, all’Agenzia e agli altri Stati membri le difficoltà infrastrutturali specifiche nell’aeroporto interessato, le misure previste per porvi rimedio e il periodo di tempo necessario per la loro attuazione.</p>\n<p class=\"norm inline-element\">Qualora sussistano difficoltà infrastrutturali specifiche che richiedono un periodo di tempo più lungo per gli adeguamenti, la Commissione, entro un mese dalla ricezione della notifica di cui al terzo comma e dopo aver consultato l’Agenzia, autorizza lo Stato membro interessato a prorogare il periodo transitorio per l’aeroporto interessato e, se del caso, stabilisce la durata di tale proroga.</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2 <span class=\"italics\">sexies</span>.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le verifiche nelle banche dati di cui al paragrafo 2, lettere a) e b), possono essere effettuate in anticipo sulla base dei dati dei passeggeri ricevuti conformemente alla direttiva 2004/82/CE del Consiglio (\n<span class=\"superscript\">13</span>\n) o ad altra normativa dell’Unione o nazionale.</p>\n<p class=\"norm inline-element\">Qualora tali verifiche siano effettuate in anticipo sulla base di tali dati dei passeggeri, i dati ricevuti anticipatamente sono verificati al valico di frontiera rispetto ai dati contenuti nel documento di viaggio. Anche l’identità e la cittadinanza dell’interessato, così come l’autenticità e la validità del documento di viaggio per l’attraversamento della frontiera, sono verificate.</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2 <span class=\"italics\">septies</span>.  </span>\n<div class=\"norm inline-element\">In deroga al paragrafo 2, i beneficiari del diritto alla libera circolazione ai sensi del diritto dell’Unione che attraversano le frontiere interne terrestri degli Stati membri per i quali è già stato completato con successo l’accertamento conformemente alle procedure di valutazione Schengen applicabili, ma per i quali non è ancora stata presa la decisione relativa alla soppressione dei controlli alle loro frontiere interne ai sensi delle pertinenti disposizioni dei rispettivi atti di adesione, possono essere soggetti alle verifiche all’uscita di cui al paragrafo 2 solo in modo non sistematico, sulla base di una valutazione dei rischi.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">All’ingresso e all’uscita, i cittadini di paesi terzi sono sottoposti a verifiche approfondite come segue:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">La verifica approfondita all’ingresso comporta la verifica delle condizioni d’ingresso di cui all’articolo 6, paragrafo 1, nonché, se del caso, dei documenti che autorizzano il soggiorno e l’esercizio di un’attività professionale. Tale verifica comprende un esame dettagliato articolato nei seguenti elementi:</p>\n<p class=\"modref\">\n▼M2\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’accertamento dell’identità e della cittadinanza del cittadino di paese terzo nonché dell’autenticità e della validità del documento di viaggio per l’attraversamento della frontiera, anche tramite consultazione delle pertinenti banche dati, in particolare:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>1) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il SIS;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>2) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la banca dati dell’Interpol SLTD;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>3) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le banche dati nazionali contenenti informazioni sui documenti di viaggio rubati, altrimenti sottratti, smarriti e invalidati.</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M3\n</p>\n<p class=\"list\">Per i passaporti e i documenti di viaggio contenenti un supporto di memorizzazione elettronica (chip), l’autenticità e l’integrità dei dati ivi memorizzati sono verificate, a condizione che siano disponibili certificati validi.</p>\n<p class=\"list\">Ad eccezione dei cittadini di paesi terzi per i quali un fascicolo individuale è già registrato nell’EES, qualora il documento di viaggio contenga un’immagine del volto registrata nel supporto di memorizzazione elettronica (chip) e a tale immagine del volto è possibile avere accesso in termini tecnici, tale accertamento include una verifica di tale immagine del volto comparandola elettronicamente all’immagine del volto del cittadino di paese terzo interessato. Se tecnicamente e giuridicamente possibile, l’accertamento può essere effettuato verificando le impronte digitali rilevate sul posto a fronte delle impronte digitali registrate nel supporto di memorizzazione elettronica (chip);</p>\n<p class=\"modref\">\n▼M2\n</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’accertamento che, all’occorrenza, il documento di viaggio sia provvisto del visto o del permesso di soggiorno richiesto;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M3\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per le persone il cui ingresso o il cui respingimento sono oggetto di registrazione nell’EES ai sensi dell’articolo 6 <span class=\"italics\">bis</span> del presente regolamento, si procede a una verifica della loro identità ai sensi dell’articolo 23, paragrafo 2, del regolamento (UE) 2017/2226 e, se del caso, a un’identificazione ai sensi dell’articolo 23, paragrafo 4, di tale regolamento;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M3\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii <span class=\"italics\">bis)</span> </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per le persone il cui ingresso o il cui respingimento è oggetto di registrazione nell’EES ai sensi dell’articolo 6 bis del presente regolamento, l’accertamento che il cittadino di paese terzo non abbia raggiunto o superato la durata massima di soggiorno autorizzato nel territorio degli Stati membri e, per i cittadini di paesi terzi titolari di un visto per rilasciato per uno o due ingressi, la verifica del rispetto del numero massimo di ingressi autorizzati, tramite consultazione dell’EES conformemente all’articolo 23 del regolamento (UE) 2017/2226;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iv) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli accertamenti relativi al luogo di partenza e di destinazione del cittadino di paese terzo interessato nonché lo scopo del soggiorno previsto e, se necessario, la verifica dei documenti giustificativi corrispondenti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>v) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’accertamento che il cittadino di paese terzo interessato disponga di mezzi di sussistenza sufficienti sia per la durata e lo scopo del soggiorno previsto, sia per il ritorno nel paese di origine o per il transito verso un paese terzo nel quale è sicuro di essere ammesso, ovvero che sia in grado di acquisire legalmente detti mezzi;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M2\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>vi) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’accertamento che il cittadino di paese terzo interessato, i suoi mezzi di trasporto e gli oggetti da esso trasportati non costituiscano un pericolo per l’ordine pubblico, la sicurezza interna, la salute pubblica o le relazioni internazionali di uno degli Stati membri. Tale accertamento comporta la consultazione diretta dei dati e delle segnalazioni relativi alle persone e, se necessario, agli oggetti inclusi nel SIS e nelle altre pertinenti banche dati dell’Unione nonché, se del caso, l’attuazione della condotta da adottare per effetto di una segnalazione. Ciò non pregiudica la consultazione delle banche dati nazionali e dell’Interpol;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">Se il cittadino di paese terzo è in possesso di un visto ai sensi dell'articolo 6, paragrafo 1, lettera b), il controllo approfondito all’ingresso comprende anche l'accertamento dell'identità del titolare del visto e dell'autenticità del visto tramite consultazione del sistema di informazione visti (VIS), conformemente all'articolo 18 del regolamento (CE) n. 767/2008;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M6\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b ter) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">Se il cittadino di paese terzo è in possesso di un visto per soggiorno di lunga durata o di un permesso di soggiorno, le verifiche approfondite all’ingresso comprendono l’accertamento dell’identità del titolare del visto per soggiorno di lunga durata e del permesso di soggiorno e della loro autenticità e validità, tramite consultazione del VIS, conformemente all’articolo 22 <span class=\"italics\">octies</span> del regolamento (CE) n. 767/2008.</p>\n<p class=\"list\">Qualora la verifica dell’identità del titolare del visto per soggiorno di lunga durata o del permesso di soggiorno o la verifica e dell’autenticità e validità del visto per soggiorno di lunga durata o del permesso di soggiorno, non dia esito ovvero sussistano dubbi circa l’identità del titolare o l’autenticità del visto per soggiorno di lunga durata o del permesso di soggiorno o del documento di viaggio, il personale debitamente autorizzato di quelle autorità competenti procede alla verifica del supporto di memorizzazione del documento;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M6 —————</p>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">La verifica approfondita all’uscita comporta:</p>\n<p class=\"modref\">\n▼M3\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la verifica dell’identità e della cittadinanza del cittadino di paese terzo, e dell’autenticità e della validità del documento di viaggio per l’attraversamento della frontiera, anche tramite consultazione delle pertinenti banche dati, in particolare:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>1) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">del SIS;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>2) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">della banca dati SLTD di Interpol;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>3) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">delle banche dati nazionali contenenti informazioni sui documenti di viaggio rubati, altrimenti sottratti, smarriti e invalidati.</p>\n</div>\n</div>\n<p class=\"list\">Per i passaporti e i documenti di viaggio contenenti un supporto di memorizzazione elettronica (chip), l’autenticità e l’integrità dei dati ivi memorizzati sono verificate, a condizione che siano disponibili certificati validi.</p>\n<p class=\"list\">Ad eccezione dei cittadini di paesi terzi per il quali un fascicolo individuale è già registrato nell’EES, qualora il documento di viaggio contenga un’immagine del volto registrata nel supporto di memorizzazione elettronica (chip) e a tale immagine del volto è possibile avere accesso in termini tecnici, tale accertamento include la verifica di tale immagine del volto comparandola elettronicamente all’immagine del volto del cittadino di paese terzo interessato rilevata sul posto. Se tecnicamente e giuridicamente possibile, detto accertamento può essere effettuato verificando le impronte digitali rilevate sul posto a fronte delle impronte digitali registrate nel supporto di memorizzazione digitale (chip);</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M2\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’accertamento che il cittadino di paese terzo non sia considerato una minaccia per l’ordine pubblico, la sicurezza interna, la salute pubblica o le relazioni internazionali di uno degli Stati membri, anche tramite consultazione del SIS e delle altre pertinenti banche dati dell’Unione. Ciò non pregiudica la consultazione delle banche dati nazionali e dell’Interpol;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M3\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per le persone la cui uscita è oggetto di registrazione nell’EES ai sensi dell’articolo 6 <span class=\"italics\">bis</span> del presente regolamento, la verifica della loro identità ai sensi dell’articolo 23, paragrafo 2, del regolamento (UE) 2017/2226 e, se del caso, un’identificazione ai sensi dell’articolo 23, paragrafo 4, di tale regolamento;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iv) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per le persone la cui uscita è oggetto di registrazione nell’EES ai sensi dell’articolo 6 <span class=\"italics\">bis</span> del presente regolamento, l’accertamento che il cittadino di paese terzo non abbia superato la durata massima di soggiorno autorizzato nel territorio degli Stati membri, tramite consultazione dell’EES conformemente all’articolo 23, paragrafo 3, del regolamento (UE) 2017/2226;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">in aggiunta alle verifiche di cui alla lettera g), la verifica approfondita all’uscita può inoltre comportare:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’accertamento che la persona sia in possesso di un visto valido, qualora richiesto ai sensi del regolamento (CE) n. 539/2001, tranne nel caso in cui sia titolare di un permesso di soggiorno valido; tale accertamento può comprendere la consultazione del VIS, conformemente all'articolo 18 del regolamento (CE) n. 767/2008;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M3 —————</p>\n<p class=\"modref\">\n▼M2 —————</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M3\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">Ai fini dell’identificazione delle persone che non soddisfano o non soddisfano più le condizioni d’ingresso, soggiorno o residenza nel territorio degli Stati membri, può essere consultato il VIS conformemente all’articolo 20 del regolamento (CE) n. 767/2008, e può essere consultato l’EES conformemente all’articolo 27 del regolamento (UE) 2017/2226.</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M2\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i bis) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le verifiche nelle banche dati di cui alla lettera a), punti i) e vi), e alla lettera g) possono essere effettuate in anticipo sulla base dei dati dei passeggeri ricevuti conformemente alla direttiva 2004/82/CE o ad altra normativa dell’Unione o nazionale.</p>\n<p class=\"list\">Qualora tali verifiche siano effettuate in anticipo sulla base dei dati dei passeggeri, i dati ricevuti anticipatamente sono verificati al valico di frontiera rispetto ai dati contenuti nel documento di viaggio. Anche l’identità e la cittadinanza dell’interessato, nonché l’autenticità e la validità del documento di viaggio per l’attraversamento della frontiera sono verificate;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i ter) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">in caso di dubbi quanto all’autenticità del documento di viaggio o all’identità del cittadino di paese terzo, le verifiche comprendono, se possibile, l’accertamento di almeno uno degli identificatori biometrici integrati nei documenti di viaggio.</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Se sono disponibili le necessarie strutture e se il cittadino di paese terzo ne fa richiesta, tali verifiche approfondite sono effettuate in un luogo non accessibile al pubblico.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4 <span class=\"italics\">bis</span>.  </span>\n<div class=\"norm inline-element\">Se, all'ingresso o all'uscita, la consultazione delle banche dati pertinenti, compreso il rilevatore di identità multiple attraverso il portale di ricerca europeo istituito dall'articolo 25, paragrafo 1, e dall'articolo 6, paragrafo 1, del regolamento (UE) 2019/817 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">14</span>\n) dà luogo, rispettivamente, a un collegamento giallo o rileva un collegamento rosso, la guardia di frontiera consulta l'archivio comune di dati di identità istituito dall'articolo 17, paragrafo 1, di tale regolamento o il SIS, o entrambi, al fine di valutare le differenze tra i dati di identità o i dati dei documenti di viaggio oggetto del collegamento. La guardia di frontiera effettua le verifiche aggiuntive necessarie per decidere sullo status e sul colore del collegamento.</div>\n</div>"], [null, "<p class=\"norm\">Conformemente all'articolo 69, paragrafo 1, del regolamento (UE) 2019/817, il presente paragrafo si applica esclusivamente a partire dall'entrata in funzione del rilevatore di identità multiple ai sensi dell'articolo 72, paragrafo 4, di tale regolamento.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Fatto salvo il secondo comma, i cittadini di paesi terzi sottoposti a una verifica approfondita in seconda linea sono informati per iscritto, in una lingua loro comprensibile o che si possa ragionevolmente supporre sia loro comprensibile, o in altro modo utile, sull'obiettivo e sulla procedura seguita per effettuare tale verifica.</div>\n</div>"], [null, "<p class=\"norm\">Tali informazioni sono disponibili in tutte le lingue ufficiali dell’Unione e nella o nelle lingue del o dei paesi limitrofi allo Stato membro interessato e indicano la possibilità per il cittadino di paese terzo di chiedere il nome o il numero di matricola delle guardie di frontiera che effettuano la verifica approfondita in seconda linea nonché il nome del valico di frontiera e la data dell’attraversamento della frontiera.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Le verifiche sui beneficiari del diritto alla libera circolazione ai sensi del diritto unionale sono effettuate a norma della direttiva 2004/38/CE.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Le modalità pratiche relative alle informazioni da registrare figurano nell’allegato II.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">In caso d'applicazione dell'articolo 5, paragrafo 2, lettere a) o b), gli Stati membri possono anche prevedere deroghe alle disposizioni stabilite nel presente articolo.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">I cittadini di paesi terzi sono informati del numero massimo di giorni del soggiorno autorizzato, che tiene conto del numero di ingressi e della durata del soggiorno autorizzati in base al visto. Tale informazione è fornita dalla guardia di frontiera al momento delle verifiche di frontiera oppure per mezzo di attrezzature, installate al valico di frontiera, che consentono al cittadino di paese terzo di consultare il servizio web di cui all’articolo 13, paragrafi 1 e 2, del regolamento (UE) 2017/2226.</div>\n</div>"]]}, "8a": {"label": "Articolo 8 bis", "heading": "Uso dei sistemi self-service per il preinserimento dei dati nell’EES", "anchor": "art_8a", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le persone il cui attraversamento della frontiera è oggetto di registrazione nell’EES conformemente all’articolo 6 <span class=\"italics\">bis</span> possono utilizzare sistemi self-service per preinserire nell’EES i dati di cui al paragrafo 4, lettera a), del presente articolo, purché siano soddisfatte tutte le seguenti condizioni:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il documento di viaggio contiene un supporto di memorizzazione elettronica (chip), e l’autenticità e l’integrità dei dati ivi memorizzati sono confermate ricorrendo alla catena completa di certificati validi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il documento di viaggio contiene un’immagine del volto registrata nel supporto di memorizzazione elettronica (chip), tecnicamente accessibile al sistema self-service in modo da permettere di accertare l’identità del titolare del documento di viaggio comparando l’immagine del volto registrata nel supporto di memorizzazione elettronica (chip) a quella rilevata sul posto; se tecnicamente e giuridicamente possibile, tale accertamento può essere effettuato verificando le impronte digitali rilevate sul posto a fronte delle impronte digitali registrate nel supporto di memorizzazione elettronica (chip) del documento di viaggio.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Conformemente al paragrafo 1 del presente articolo, il sistema self-service verifica se la persona è già registrata nell’EES e accerta l’identità del cittadino di paese terzo ai sensi dell’articolo 23, paragrafo 2, del regolamento (UE) 2017/2226.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Conformemente all’articolo 23, paragrafo 4, del regolamento (UE) 2017/2226, il sistema self-service procede a un’identificazione conformemente all’articolo 27 di tale regolamento.</div>\n</div>"], [null, "<p class=\"norm inline-element\">Inoltre, conformemente all’articolo 23, paragrafo 4, del regolamento (UE) 2017/2226, quando è effettuata un’identificazione nell’EES</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per quanto riguarda i cittadini di paesi terzi soggetti all’obbligo del visto ai fini dell’attraversamento delle frontiere esterne, se l’interrogazione nel VIS con i dati di cui all’articolo 18, paragrafo 1, del regolamento (CE) n. 767/2008 indica che la persona è registrata nel VIS, è effettuata una verifica delle impronte digitali nei dati del VIS ai sensi dell’articolo 18, paragrafo 6, del regolamento (CE) n. 767/2008. Qualora la verifica sulla persona ai sensi del paragrafo 2 del presente articolo non abbia dato esito, si dovrebbe accedere ai dati del VIS a fini di identificazione ai sensi dell’articolo 20 del regolamento (CE) n. 767/2008;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per i cittadini di paesi terzi non soggetti all’obbligo del visto ai fini dell’attraversamento delle frontiere esterne e che non risultano registrati nell’EES a seguito dell’identificazione effettuata ai sensi dell’articolo 27 del regolamento (UE) 2017/2226, è consultato il VIS conformemente all’articolo 19 <span class=\"italics\">bis</span> del regolamento (CE) n. 767/2008.</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Nel caso in cui i dati relativi alla persona di cui al paragrafo 1 del presente articolo non siano registrati nell’EES ai sensi dei paragrafi 2 e 3:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i cittadini di paesi terzi soggetti all’obbligo del visto ai fini dell’attraversamento delle frontiere esterne procedono a preinserire nell’EES, tramite il sistema self-service, i dati elencati all’articolo 16, paragrafo 1 e all’articolo 16, paragrafo 2, lettere da c), a f) del regolamento (UE) 2017/2226 e, se del caso, i dati di cui all’articolo 16, paragrafo 6, di tale regolamento, e i cittadini di paesi terzi non soggetti all’obbligo del visto ai fini dell’attraversamento delle frontiere esterne procedono a preinserire nell’EES, tramite il sistema self-service, i dati elencati all’articolo 17, paragrafo 1, lettere a), b) e c) e all’articolo 16, paragrafo 2, lettera c) di tale regolamento e, se del caso, i dati di cui all’articolo 17, paragrafo 1, lettera d), di tale regolamento;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la persona è in seguito indirizzata verso una guardia di frontiera che:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">procede al preinserimento dei dati interessati, qualora non sia stato possibile raccogliere tutti i dati necessari tramite il sistema self-service;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">verifica:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">che il documento di viaggio utilizzato al sistema self-service corrisponda a quello in possesso della persona al suo cospetto,</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">che l’immagine del volto della persona interessata rilevata sul posto corrisponda all’immagine del volto raccolta tramite il sistema self-service, e</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">per le persone che non sono in possesso del visto richiesto ai sensi del regolamento (CE) n. 539/2001, che le impronte digitali dell’interessato rilevate sul posto corrispondano a quelle raccolte tramite il sistema self-service;</div>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una volta presa la decisione di autorizzare l’ingresso della persona o di respingerla, conferma i dati di cui alla lettera a) del presente paragrafo e inserisce nell’EES i dati di cui all’articolo 16, paragrafo 2, lettere a) e b) e all’articolo 18, paragrafo 6, lettere a), b), c) e d) del regolamento (UE) 2017/2226.</p>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Quando, le operazioni previste ai paragrafi 2 e 3 indicano che i dati relativi alla persona di cui al paragrafo 1 sono registrati nell’EES, il sistema self-service valuta se sia necessario un aggiornamento di ciascuno dei dati di cui al paragrafo 4, lettera a).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Qualora la valutazione di cui al paragrafo 5 riveli che la persona di cui al paragrafo 1 ha un fascicolo individuale registrato nell’EES ma che i suoi dati devono essere aggiornati, la persona:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">aggiorna i dati nell’EES preinserendoli tramite il sistema self-service;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">viene indirizzata verso una guardia di frontiera, che verifica la correttezza dell’aggiornamento ai sensi della lettera a) del presente paragrafo e, una volta presa la decisione di autorizzare l’ingresso della persona o respingerla, aggiorna il fascicolo individuale conformemente all’articolo 14, paragrafo 2, del regolamento (UE) 2017/2226.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">I sistemi self-service funzionano sotto la sorveglianza di una guardia di frontiera incaricata di rilevare qualsiasi uso inappropriato, fraudolento o anormale del sistema self-service.</div>\n</div>"]]}, "8b": {"label": "Articolo 8 ter", "heading": "Uso di sistemi self-service e di varchi automatici per l’attraversamento della frontiera da parte di persone il cui attraversamento della frontiera è oggetto di registrazione nell’EES", "anchor": "art_8b", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le persone il cui attraversamento della frontiera è oggetto di registrazione nell’EES conformemente all’articolo 6 <span class=\"italics\">bis</span> possono essere autorizzate a usare un sistema self-service per effettuare le verifiche di frontiera qualora siano soddisfatte tutte le seguenti condizioni:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il documento di viaggio contiene un supporto di memorizzazione elettronica (chip), e l’autenticità e l’integrità dei dati ivi memorizzati sono confermate ricorrendo alla catena completa di certificati validi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il documento di viaggio contiene un’immagine del volto registrata nel supporto di memorizzazione elettronica (chip), tecnicamente accessibile al sistema self-service in modo da permettere di verificare l’identità del titolare del documento di viaggio comparando tale immagine del volto con quella rilevata sul posto; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la persona è già registrata o i suoi dati sono stati preinseriti nell’EES.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Se ricorrono le condizioni stabilite al paragrafo 1 del presente articolo, le verifiche di frontiera all’ingresso previste all’articolo 8, paragrafo 2, e all’articolo 8, paragrafo 3, lettere a) e b), e le verifiche di frontiera all’uscita previste all’articolo 8, paragrafo 2, e all’articolo 8, paragrafo 3, lettere g) e h), possono avvenire tramite un sistema self-service. Quando sono effettuate tramite un sistema di controllo di frontiera automatizzato, le verifiche di frontiera all’uscita includono le verifiche previste all’articolo 8, paragrafo 3, lettera h).</div>\n</div>"], [null, "<p class=\"norm\">Qualora una persona sia ammessa a un programma nazionale di facilitazione istituito da uno Stato membro ai sensi dell’articolo 8 <span class=\"italics\">quinquies</span>, le verifiche di frontiera effettuate attraverso un sistema self-service all’ingresso possono omettere l’esame degli aspetti previsti all’articolo 8, paragrafo 3, lettera a), punti iv) e v), quando tale persona attraversa le frontiere esterne di tale Stato membro o le frontiere esterne di un altro Stato membro che abbia concluso un accordo con lo Stato membro che ha concesso l’accesso di cui all’articolo 8 <span class=\"italics\">quinquies</span>, paragrafo 9.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">All’ingresso e all’uscita, i risultati delle verifiche di frontiera effettuate attraverso il sistema self-service sono messi a disposizione di una guardia di frontiera. Tale guardia di frontiera monitora i risultati delle verifiche di frontiera e, tenendo conto di tali risultati, autorizza l’ingresso o l’uscita o, diversamente, indirizza la persona verso una guardia di frontiera che procede a ulteriori verifiche.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La persona in questione è indirizzata verso una guardia di frontiera a norma del paragrafo 3 in ciascuna delle seguenti situazioni:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">qualora una o più delle condizioni di cui al paragrafo 1 non siano soddisfatte;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">qualora dalle verifiche all’ingresso o all’uscita previste al paragrafo 2 emerge che non siano soddisfatte una o più delle condizioni di ingresso o di uscita;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">qualora i risultati delle verifiche all’ingresso o all’uscita previste al paragrafo 2 mettano in dubbio l’identità della persona, o quando rivelino che la persona è considerata una minaccia per la sicurezza interna, l’ordine pubblico, le relazioni internazionali di ogni gli Stato membro, oppure per la salute pubblica;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">in caso di dubbi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">qualora non siano disponibili varchi automatici.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Oltre alle situazioni indicate al paragrafo 4, la guardia di frontiera che sorveglia l’attraversamento della frontiera può decidere, sulla base di altri motivi, di indirizzare la persona che utilizza il sistema self-service verso un’altra guardia di frontiera.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Le persone il cui attraversamento della frontiera è oggetto di registrazione nell’EES conformemente all’articolo 6 <span class=\"italics\">bis</span>, paragrafo 1, e che hanno utilizzato un sistema self-service per effettuare le verifiche di frontiera, possono essere autorizzate a usare un varco automatico. In caso di utilizzo di un varco automatico, la corrispondente registrazione della cartella di ingresso/uscita e il collegamento di tale cartella al corrispondente fascicolo individuale ai sensi dell’articolo 14 del regolamento (UE) 2017/2226 avvengono al momento dell’attraversamento della frontiera tramite il varco automatico. Se il varco automatico e il sistema self-service sono fisicamente separati, presso tale varco è svolto un accertamento dell’identità dell’utente per verificare che la persona che lo utilizza corrisponda alla persona che ha utilizzato il sistema self-service. L’accertamento è eseguito usando almeno un identificatore biometrico.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Qualora le condizioni elencate al paragrafo 1, lettera a) o b), o entrambe, non siano soddisfatte, può essere effettuata tramite un sistema self-service una parte delle verifiche di frontiera all’ingresso previste all’articolo 8, paragrafo 3, lettere a) e b), e una parte delle verifiche di frontiera all’uscita previste all’articolo 8, paragrafo 3, lettere g) e h). La guardia di frontiera può limitarsi a procedere solo a quegli accertamenti previsti all’articolo 8, paragrafo 3, lettere a) e b), e all’articolo 8, paragrafo 3, lettere g) e h), che non è stato possibile effettuare attraverso il sistema self-service. La guardia di frontiera accerta inoltre che il documento di viaggio usato al sistema self-service corrisponda a quello in possesso della persona al cospetto di tale guardia di frontiera.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">I sistemi self-service e i varchi automatici funzionano sotto la sorveglianza di una guardia di frontiera incaricata di rilevare qualsiasi uso inappropriato, fraudolento o anormale del sistema self-service, del varco automatico, o di entrambi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">Il presente articolo lascia impregiudicata la possibilità, per gli Stati membri, di consentire l’uso di sistemi self-service, di varchi automatici, o entrambi, per l’attraversamento della frontiera da parte dei cittadini dell’Unione, dei cittadini di uno Stato dell’Associazione europea di libero scambio dello Spazio economico europeo, dei cittadini della Svizzera e dei cittadini di paesi terzi il cui attraversamento della frontiera non è oggetto di una registrazione nell’EES.</div>\n</div>"]]}, "8c": {"label": "Articolo 8 quater", "heading": "Norme relative ai sistemi di controllo di frontiera automatizzato", "anchor": "art_8c", "frags": [[null, "<p class=\"norm\">I sistemi di controllo di frontiera automatizzato sono progettati, nella misura del possibile, in modo tale da poter essere utilizzati da qualsiasi persona, a eccezione dei minori di età inferiore a 12 anni. Sono altresì progettati in modo da garantire il pieno rispetto della dignità umana, in particolare nei casi concernenti persone vulnerabili. Allorché gli Stati membri decidono di avvalersi di sistemi di controllo di frontiera automatizzato, essi garantiscono la presenza di personale in numero sufficiente per assistere le persone nell’utilizzo di tali sistemi.</p>"]]}, "8d": {"label": "Articolo 8 quinquies", "heading": "Programmi nazionali di facilitazione", "anchor": "art_8d", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ciascuno Stato membro può istituire un programma volontario (« programma nazionale di facilitazione») per consentire ai cittadini di paesi terzi, ai cittadini di uno specifico paese terzo, che non godono del diritto di libera circolazione ai sensi del diritto dell’Unione di beneficiare delle facilitazioni previste al paragrafo 2 all’atto dell’attraversamento delle frontiere esterne di uno Stato membro.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">In deroga all’articolo 8, paragrafo 3, lettera a), per i cittadini di paesi terzi di cui al paragrafo 1 del presente articolo che sono stati ammessi al programma nazionale di facilitazione, le verifiche approfondite all’ingresso non devono includere un esame degli aspetti previsti all’articolo 8, paragrafo 3, lettera a), punti iv) e v), quando tali cittadini di paesi terzi attraversano le frontiere esterne di uno Stato membro.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Lo Stato membro sottopone a un controllo preliminare di sicurezza i cittadini di paesi terzi che chiedono di essere ammessi al programma nazionale di facilitazione al fine di verificare, in particolare, che le condizioni di cui al paragrafo 4 siano soddisfatte.</div>\n</div>"], [null, "<p class=\"norm\">Tali cittadini di paesi terzi sono sottoposti al controllo preliminare di sicurezza da parte delle guardie di frontiera, delle autorità competenti per i visti quali definite all’articolo 4, punto 3, del regolamento (CE) n. 767/2008 o delle autorità competenti per l’immigrazione quali definite all’articolo 3, paragrafo 1, punto 4, del regolamento (UE) 2017/2226.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le autorità di cui al paragrafo 3 accordano a una persona l’accesso al programma nazionale di facilitazione solo qualora siano soddisfatte tutte le seguenti condizioni:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il richiedente soddisfa le condizioni d’ingresso di cui all’articolo 6, paragrafo 1;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il documento di viaggio del richiedente e, se applicabile, il visto, il visto per soggiorno di lunga durata o il permesso di soggiorno sono validi e non sono falsi, contraffatti o alterati;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il richiedente dimostra la necessità di viaggiare frequentemente o regolarmente o giustifica la propria intenzione di viaggiare frequentemente o regolarmente;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il richiedente dimostra la propria integrità e affidabilità, in particolare, se del caso, dimostra di aver utilizzato in maniera lecita i precedenti visti o visti con validità territoriale limitata, dimostra la propria situazione economica nel paese d’origine e l’effettiva intenzione di lasciare il territorio degli Stati membri prima del termine del periodo di soggiorno autorizzato. Conformemente all’articolo 25 del regolamento (UE) 2017/2226, le autorità di cui al paragrafo 3 del presente articolo hanno accesso all’EES per verificare che il richiedente non abbia precedentemente superato la durata massima di soggiorno autorizzato nel territorio degli Stati membri;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il richiedente giustifica lo scopo e le condizioni del soggiorno previsto;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il richiedente dispone di mezzi di sussistenza sufficienti, sia per la durata dei soggiorni previsti sia per il ritorno nel paese di origine o di residenza, o è in grado di ottenere lecitamente detti mezzi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">viene consultato il SIS.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Il primo accesso al programma nazionale di facilitazione è concesso per un periodo massimo di un anno. L’accesso può essere prorogato per altri cinque anni al massimo oppure fino al termine del periodo di validità del documento di viaggio o di un eventuale visto per ingressi multipli, visto per soggiorno di lunga durata e permesso di soggiorno rilasciato, se più breve.</div>\n</div>"], [null, "<p class=\"norm\">In caso di proroga, ogni anno lo Stato membro valuta nuovamente la situazione di ciascun cittadino di paese terzo ammesso al programma nazionale di facilitazione per garantire che, in base alle informazioni aggiornate, tale cittadino di paese terzo interessato continui a soddisfare le condizioni di cui al paragrafo 4. Tale nuova valutazione può essere effettuata quando sono effettuate le verifiche di frontiera.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Le verifiche approfondite all’ingresso di cui all’articolo 8, paragrafo 3, lettera a), e lettera b), e le verifiche approfondite all’uscita di cui all’articolo 8, paragrafo 3, lettera g), comprendono anche l’accertamento del fatto che il cittadino di paese terzo abbia un valido accesso al programma nazionale di facilitazione.</div>\n</div>"], [null, "<p class=\"norm\">Le guardie di frontiera possono effettuare la verifica sul cittadino di paese terzo che beneficia del programma nazionale di facilitazione all’ingresso ai sensi dell’articolo 8, paragrafo 3, lettera a) e lettera b), e all’uscita ai sensi dell’articolo 8, paragrafo 3, lettera g), senza comparare elettronicamente i dati biometrici, ma confrontando l’immagine del volto ricavata dal supporto di memorizzazione elettronica (chip) e l’immagine del volto contenuta nel fascicolo individuale EES del cittadino di paese terzo con tale faccia del cittadino di paese terzo. La verifica completa è effettuata in modo casuale e in base a un’analisi dei rischi.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Le autorità di cui al paragrafo 3 revocano immediatamente l’accesso al programma nazionale di facilitazione accordato a un cittadino di paese terzo se risulti che le condizioni di accesso a tale programma non erano soddisfatte o non sono più soddisfatte.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Nel verificare, in conformità del paragrafo 3, se il richiedente soddisfa le condizioni di cui al paragrafo 4, si valuta con particolare attenzione se questi presenti un rischio di immigrazione illegale o un rischio per la sicurezza di ciascuno degli Stati membri e se intenda lasciare il territorio degli Stati membri entro la scadenza del soggiorno autorizzato.</div>\n</div>"], [null, "<p class=\"norm\">La valutazione dei mezzi di sussistenza per i soggiorni previsti si effettua in funzione della durata e dello scopo del soggiorno o dei soggiorni previsti e con riferimento ai prezzi medi vigenti nello Stato membro o negli Stati membri interessati per vitto e alloggio in sistemazione economica, in base agli importi di riferimento fissati dagli Stati membri conformemente all’articolo 39, paragrafo 1, lettera c). Una dichiarazione di garanzia, di alloggio da parte di un privato, o entrambe, possono altresì costituire una prova della disponibilità di mezzi di sussistenza sufficienti.</p>"], [null, "<p class=\"norm\">L’esame di una domanda si fonda, in particolare, sull’autenticità e l’affidabilità dei documenti presentati e sulla veridicità e l’affidabilità delle dichiarazioni fatte dal richiedente. In caso di dubbi sul richiedente, sulle sue dichiarazioni o sui documenti giustificativi presentati, lo Stato membro competente per l’esame di una domanda può consultare altri Stati membri prima di decidere in merito alla stessa.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">Due o più Stati membri che abbiano istituito il proprio programma nazionale di facilitazione ai sensi del presente articolo possono stipulare fra di loro un accordo per garantire che i beneficiari dei loro programmi nazionali di facilitazione possano godere delle facilitazioni riconosciute da un altro programma nazionale di facilitazione. Entro il termine di un mese dalla conclusione dell’accordo, ne è trasmessa una copia alla Commissione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">10.  </span>\n<div class=\"norm inline-element\">Nell’istituire un programma nazionale di facilitazione, gli Stati membri garantiscono che il loro sistema di funzionamento del programma rispetti le norme di sicurezza dei dati previste all’articolo 43 del regolamento (UE) 2017/2226. Gli Stati membri effettuano un’adeguata valutazione del rischio connesso alla sicurezza delle informazioni e le responsabilità in materia di sicurezza sono illustrate in modo chiaro per tutte le fasi del processo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">11.  </span>\n<div class=\"norm inline-element\">Entro la fine del terzo anno di applicazione del presente articolo, la Commissione trasmette al Parlamento europeo e al Consiglio una valutazione della sua attuazione. Sulla base di tale valutazione, il Parlamento europeo o il Consiglio possono invitare la Commissione a proporre l’istituzione di un programma dell’Unione per cittadini di paesi terzi che siano viaggiatori frequenti e siano stati sottoposti a controllo preliminare di sicurezza.</div>\n</div>"]]}, "9": {"label": "Articolo 9", "heading": "Snellimento delle verifiche di frontiera", "anchor": "art_9", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">In circostanze eccezionali ed impreviste le verifiche di frontiera alle frontiere esterne possono essere snellite. Tali circostanze eccezionali ed impreviste sono considerate sussistere quando eventi imprevedibili provocano un’intensità di traffico tale da rendere eccessivi i tempi di attesa ai valichi di frontiera e sono state sfruttate tutte le risorse in termini di organizzazione, di mezzi e di personale.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">In caso di snellimento delle verifiche di frontiera a norma del paragrafo 1, le verifiche di frontiera all’ingresso hanno, in linea di principio, la precedenza sulle verifiche di frontiera all’uscita.</div>\n</div>"], [null, "<p class=\"norm\">La decisione di snellire le verifiche è presa dalla guardia di frontiera che esercita il comando presso il valico di frontiera.</p>"], [null, "<p class=\"norm\">Tale snellimento è temporaneo, adattato alle circostanze che lo giustificano e attuato progressivamente.</p>"], [null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Anche in caso di snellimento delle verifiche, la guardia di frontiera inserisce i dati nell’EES a norma dell’articolo 6 <span class=\"italics\">bis</span>. Qualora non possano essere inseriti con mezzi elettronici, i dati sono inseriti manualmente.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3 <span class=\"italics\">bis</span>.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Qualora sia impossibile tecnicamente inserire i dati nel sistema centrale dell’EES o in caso di guasto del sistema centrale dell’EES, si applicano tutte le seguenti disposizioni:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">in deroga all’articolo 6 <span class=\"italics\">bis</span> del presente regolamento, i dati di cui agli articoli da 16 a 20 del regolamento (UE) 2017/2226 sono temporaneamente conservati nell’interfaccia uniforme nazionale definita all’articolo 7 di tale regolamento. Qualora ciò non sia possibile, i dati sono temporaneamente conservati localmente in un formato elettronico. In entrambi i casi, i dati sono inseriti nel sistema centrale dell’EES non appena l’impossibilità tecnica o il guasto siano stati risolti. Gli Stati membri adottano le misure appropriate e predispongono le infrastrutture, le attrezzature e le risorse necessarie per garantire che si possa procedere a tale conservazione locale temporanea in ogni momento e per ciascuno dei loro valichi di frontiera.</p>\n<p class=\"list\">Fatto salvo l’obbligo di procedere alle verifiche di frontiera ai sensi del presente regolamento, nel caso eccezionale in cui sia tecnicamente impossibile inserire i dati nel sistema centrale dell’EES e nell’interfaccia uniforme nazionale e sia tecnicamente impossibile conservare temporaneamente i dati localmente in un formato elettronico, la guardia di frontiera conserva manualmente i dati di ingresso/uscita in conformità degli articoli da 16 a 20 del regolamento (UE) 2017/2226, a eccezione dei dati biometrici, e appone un timbro d’ingresso o di uscita sul documento di viaggio del cittadino di paese terzo. Tali dati sono inseriti nel sistema centrale dell’EES non appena tecnicamente possibile.</p>\n<p class=\"list\">Gli Stati membri informano la Commissione, in conformità dell’articolo 21, paragrafo 2, del regolamento (UE) 2017/2226, in merito all’apposizione di timbri sui documenti di viaggio qualora si verifichino casi eccezionali di cui al secondo comma del presente punto;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">in deroga all’articolo 8, paragrafo 3, lettera a), punto iii), e lettera g), punto iv), del presente regolamento per i cittadini di paesi terzi in possesso di un visto di cui all’articolo 6, paragrafo 1, lettera b), qualora ciò sia tecnicamente possibile, l’accertamento dell’identità del titolare del visto è effettuato consultando direttamente il VIS conformemente all’articolo 18 del regolamento (CE) n. 767/2008.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Ciascuno Stato membro trasmette annualmente al Parlamento europeo e alla Commissione una relazione sull’applicazione del presente articolo.</div>\n</div>"]]}, "10": {"label": "Articolo 10", "heading": "Allestimento di corsie separate e segnaletica", "anchor": "art_10", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli Stati membri allestiscono corsie separate, in particolare ai valichi delle frontiere aeree al fine di poter procedere alle verifiche sulle persone a norma dell’articolo 8. Tali corsie sono differenziate mediante una segnaletica recante le indicazioni di cui all’allegato III.</div>\n</div>"], [null, "<p class=\"norm\">Gli Stati membri possono allestire corsie separate ai valichi delle loro frontiere marittime e terrestri e alle frontiere tra gli Stati membri che non applicano l’articolo 22 alle loro frontiere comuni. Se gli Stati membri allestiscono corsie separate a tali frontiere, utilizzano una segnaletica recante le indicazioni di cui all’allegato III.</p>"], [null, "<p class=\"norm\">Gli Stati membri assicurano che tali corsie siano indicate con una segnaletica chiara, anche in caso di sospensione delle norme relative all’utilizzo delle corsie separate a norma del paragrafo 4, al fine di garantire il flusso ottimale delle persone che attraversano la frontiera.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I beneficiari del diritto alla libera circolazione ai sensi del diritto unionale sono autorizzati a servirsi delle corsie indicate dal pannello di cui alla parte A («UE, SEE, CH») dell’allegato III. Possono altresì servirsi delle corsie indicate dal pannello di cui alla parte B1 («visto non richiesto») e alla parte B2 («tutti i passaporti») dell’allegato III.</div>\n</div>"], [null, "<p class=\"norm\">I cittadini di paesi terzi non tenuti a possedere un visto all'atto dell'attraversamento delle frontiere esterne degli Stati membri conformemente al regolamento (CE) n. 539/2001, e i cittadini di paesi terzi titolari di un permesso di soggiorno o di un visto per soggiorno di lunga durata in corso di validità possono servirsi delle corsie indicate dal pannello di cui alla parte B1 («visto non richiesto») dell'allegato III del presente regolamento. Possono altresì servirsi delle corsie indicate dal pannello di cui alla parte B2 («tutti i passaporti») dell'allegato III del presente regolamento.</p>"], [null, "<p class=\"norm\">Tutte le altre persone si servono delle corsie indicate dal pannello di cui alla parte B2 («tutti i passaporti») dell’allegato III.</p>"], [null, "<p class=\"norm\">Le indicazioni sui pannelli di cui al primo, secondo e terzo comma possono figurare nella o nelle lingue ritenute appropriate da ciascuno Stato membro.</p>"], [null, "<p class=\"norm\">L'allestimento di corsie separate indicate dal pannello di cui alla parte B1 («visto non richiesto») dell'allegato III non è obbligatorio. Gli Stati membri decidono se utilizzarla o meno e a quali valichi di frontiera in base alle esigenze pratiche.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Ai valichi delle frontiere marittime e terrestri gli Stati membri possono separare il traffico di veicoli allestendo corsie distinte per i veicoli leggeri, gli automezzi pesanti e gli autobus, a mezzo dei pannelli di cui all’allegato III, parte C.</div>\n</div>"], [null, "<p class=\"norm\">Gli Stati membri possono, se del caso, modificare le indicazioni figuranti su tali pannelli in base alle circostanze locali.</p>"], [null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3 <span class=\"italics\">bis</span>.  </span>\n<div class=\"norm inline-element\">Qualora decidano di usare varchi automatici, sistemi self-service, o sistemi automatici di controllo delle frontiere, gli Stati membri contrassegnano le rispettive corsie con la segnaletica di cui alla parte D dell’allegato III.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3 <span class=\"italics\">ter</span>.  </span>\n<div class=\"norm inline-element\">Qualora decidano di istituire un programma nazionale di facilitazione in conformità dell’articolo 8 <span class=\"italics\">quinquies</span>, gli Stati membri possono decidere di utilizzare corsie specifiche per i cittadini di paesi terzi che beneficiano di tale programma nazionale di facilitazione. Contrassegnano le rispettive corsie con la segnaletica di cui alla parte E dell’allegato III.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">In caso di squilibrio temporaneo nei flussi di traffico ad un determinato valico di frontiera, le norme relative all’utilizzo delle corsie separate possono essere sospese dalle autorità competenti per il tempo necessario al ristabilimento dell’equilibrio.</div>\n</div>"]]}, "11": {"label": "Articolo 11", "heading": "Apposizione di timbri sui documenti di viaggio", "anchor": "art_11", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Qualora espressamente previsto dal diritto nazionale, uno Stato membro, al momento dell’ingresso e dell’uscita, può apporre un timbro sul documento di viaggio dei cittadini di paesi terzi titolari di un permesso di soggiorno o di un visto per soggiorno di lunga durata rilasciato da detto Stato membro.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il documento di viaggio di un cittadino di paese terzo che è in possesso di un documento di transito ferroviario agevolato rilasciato a norma del regolamento (CE) n. 693/2003 è timbrato al momento dell’ingresso e dell’uscita. Inoltre, il documento di viaggio di un cittadino di paese terzo che è in possesso di un documento di transito agevolato valido rilasciato a norma del regolamento (CE) n. 693/2003 e che transita via treno e che non scende sul territorio di uno Stato membro è timbrato all’ingresso e all’uscita.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">I documenti di viaggio di cittadini di paesi terzi che entrano nel territorio di uno Stato membro che non applica ancora integralmente l’acquis di Schengen ma in cui l’EES è operativo, o escono dallo stesso, sulla base di un visto nazionale per soggiorno di breve durata rilasciato per uno o due ingressi, sono timbrati all’ingresso e all’uscita.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Le modalità pratiche dell’apposizione del timbro sono stabilite nell’allegato IV.</div>\n</div>"]]}, "12": {"label": "Articolo 12", "heading": "Presunzione in ordine al soddisfacimento delle condizioni relative alla durata del soggiorno di breve durata", "anchor": "art_12", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Fatto salvo l’articolo 12 <span class=\"italics\">bis</span>, se non è stato creato alcun fascicolo individuale nell’EES per un cittadino di paese terzo presente nel territorio di uno Stato membro o se la cartella di ingresso/uscita di tale cittadino di paese terzo non contiene una data di uscita successiva alla data di scadenza della durata del soggiorno autorizzato, le autorità competenti possono presumere che il cittadino di paese terzo non soddisfi o non soddisfi più le condizioni di durata del soggiorno autorizzato nel territorio degli Stati membri.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La presunzione di cui al paragrafo 1 del presente articolo non si applica al cittadino di paese terzo che può fornire, in qualsiasi modo, elementi di prova attendibili che dimostrino che lo stesso beneficia del diritto alla libera circolazione ai sensi del diritto dell’Unione o che è titolare di un permesso di soggiorno o di un visto per soggiorni di lunga durata. Se necessario, si applica l’articolo 35 del regolamento (UE) 2017/2226.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La presunzione di cui al paragrafo 1 può essere confutata qualora il cittadino di paese terzo fornisca, in qualsiasi modo, elementi di prova attendibili, come biglietti di viaggio o giustificativi della presenza fuori del territorio degli Stati membri o della data di scadenza di un precedente permesso di soggiorno o di un precedente visto per soggiorni di lunga durata, che dimostrino che ha rispettato le condizioni relative alla durata di un soggiorno di breve durata.</div>\n</div>"], [null, "<p class=\"norm\">In caso di confutazione, le autorità competenti costituiscono un fascicolo individuale nell’EES, se necessario, o indicano nell’EES la data e il luogo in cui il cittadino di paese terzo ha attraversato la frontiera esterna di uno degli Stati membri o la frontiera interna di uno Stato membro che non applica ancora integralmente l’acquis di Schengen ma in cui l’EES è operativo, ai sensi dell’articolo 20 del regolamento (UE) 2017/2226.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Qualora la presunzione di cui al paragrafo 1 non dovesse essere confutata, un cittadino di paese terzo presente nel territorio degli Stati membri può essere rimpatriato conformemente alla direttiva 2008/115/CE del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">*5</span>\n).</div>\n</div>"], [null, "<p class=\"norm\">Un cittadino di paese terzo che beneficia del diritto alla libera circolazione a norma del diritto dell’Unione può essere rimpatriato solo conformemente alla direttiva 2004/38/CE.</p>"]]}, "12a": {"label": "Articolo 12 bis", "heading": "Periodo transitorio e misure transitorie", "anchor": "art_12a", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Per un periodo di 180 giorni dopo l’entrata in funzione dell’EES, al fine di verificare, all’atto dell’ingresso e dell’uscita, che le persone ammesse per un soggiorno di breve durata non abbiano oltrepassato la durata massima del soggiorno autorizzato e, se necessario, di verificare che all’atto dell’ingresso tali persone non abbiano superato il numero di ingressi autorizzati da un visto per un soggiorno di breve durata rilasciato per uno o due ingressi le guardie di frontiera tengono conto dei soggiorni nel territorio degli Stati membri nei 180 giorni che precedono l’ingresso o l’uscita verificando i timbri sui documenti di viaggio, in aggiunta ai dati di ingresso/uscita registrati nell’EES.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Qualora una persona sia entrata nel territorio degli Stati membri prima che l’EES sia entrato in funzione, e ne sia uscita dopo che l’EES sia entrato in funzione, all’atto di uscita è costituito nell’EES un fascicolo individuale e la data di tale ingresso è inserita nella cartella di ingresso/uscita conformemente all’articolo 16, paragrafo 2, del regolamento (UE) 2017/2226. L’applicazione del presente paragrafo non è limitata al periodo di 180 giorni dopo l’entrata in funzione dell’EES di cui al paragrafo 1. In caso di una divergenza fra la data del timbro di ingresso e i dati registrati nell’EES, prevale la data del timbro di ingresso.</div>\n</div>"]]}, "13": {"label": "Articolo 13", "heading": "Sorveglianza di frontiera", "anchor": "art_13", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La sorveglianza si prefigge principalmente lo scopo di impedire o individuare l’attraversamento non autorizzato della frontiera, di contribuire ad accrescere la conoscenza situazionale, di lottare contro la criminalità transfrontaliera e di prendere misure contro le persone entrate illegalmente. Essa comporta altresì la realizzazione di analisi dei rischi. Fatti salvi gli articoli 3 e 4, una persona che ha attraversato illegalmente una frontiera e che non ha il diritto di soggiornare sul territorio dello Stato membro interessato è rintracciata ed è sottoposta a procedure che rispettano la direttiva 2008/115/CE.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le guardie di frontiera si servono di tutte le risorse necessarie, ivi comprese unità fisse o mobili per effettuare la sorveglianza di frontiera. La sorveglianza di frontiera viene effettuata in modo da impedire alle persone l’attraversamento non autorizzato della frontiera ai valichi di frontiera o di eludere le verifiche ai valichi di frontiera e da dissuaderle dal farlo, ed è eseguita nel pieno rispetto degli obblighi di cui all’articolo 4.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La sorveglianza tra i valichi di frontiera è effettuata da guardie di frontiera in numero e con metodi adatti ai rischi e alle minacce esistenti o previsti. Si avvale di quadri situazionali per essere maggiormente in grado di ridurre la perdita di vite umane dei migranti alle frontiere esterne, lungo le stesse o in loro prossimità. Essa comporta cambiamenti frequenti e improvvisi dei periodi di sorveglianza e di altri metodi e tecniche, in modo da individuare o impedire efficacemente l’attraversamento non autorizzato della frontiera.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La sorveglianza è effettuata da unità fisse o mobili che svolgono i loro compiti pattugliando o appostandosi in luoghi riconosciuti come sensibili o supposti tali. Lo scopo di tale sorveglianza è impedire l’attraversamento non autorizzato della frontiera o rintracciare le persone connesse a un attraversamento non autorizzato della frontiera esterna. La sorveglianza può essere effettuata facendo ricorso anche a mezzi tecnici, compresi dispositivi elettronici, attrezzature, sistemi di sorveglianza e, se del caso, tutti i tipi di infrastrutture fisse e mobili.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all’articolo 37 riguardo a modalità di sorveglianza supplementari, comprese norme minime comuni per la sorveglianza di frontiera. Tali norme minime comuni dovrebbero tenere conto del tipo di frontiera, ossia frontiera terrestre, marittima o aerea, del livello di impatto attribuito a ciascuna sezione di frontiera esterna conformemente all’articolo 34 del regolamento (UE) 2019/1896 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">15</span>\n) e di altri fattori rilevanti, quali le specificità geografiche.</div>\n</div>"]]}, "14": {"label": "Articolo 14", "heading": "Respingimento", "anchor": "art_14", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Sono respinti dal territorio degli Stati membri i cittadini di paesi terzi che non soddisfino tutte le condizioni d’ingresso previste dall’articolo 6, paragrafo 1, e non rientrino nelle categorie di persone di cui all’articolo 6, paragrafo 5. Ciò non pregiudica l’applicazione di disposizioni particolari relative al diritto d’asilo e alla protezione internazionale o al rilascio di visti per soggiorno di lunga durata.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il respingimento può essere disposto solo con un provvedimento motivato che ne indichi le ragioni precise. Il provvedimento è adottato da un’autorità competente secondo la legislazione nazionale ed è d’applicazione immediata.</div>\n</div>"], [null, "<p class=\"norm\">Il provvedimento motivato indicante le ragioni precise del respingimento è notificato a mezzo del modello uniforme di cui all’allegato V, parte B, compilato dall’autorità che, secondo la legislazione nazionale, è competente a disporre il respingimento. Il modello uniforme compilato è consegnato al cittadino di paese terzo interessato, il quale accusa ricevuta del provvedimento a mezzo del medesimo modello uniforme.</p>"], [null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<p class=\"norm\">I dati relativi ai cittadini di paesi terzi a cui è stato rifiutato l’ingresso per un soggiorno di breve durata sono registrati nell’EES conformemente all’articolo 6 <span class=\"italics\">bis</span>, paragrafo 2, del presente regolamento, e all’articolo 18 del regolamento (UE) 2017/2226.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Le persone respinte hanno il diritto di presentare ricorso. I ricorsi sono disciplinati conformemente alla legislazione nazionale. Al cittadino di paese terzo sono altresì consegnate indicazioni scritte riguardanti punti di contatto in grado di fornire informazioni su rappresentanti competenti ad agire per conto del cittadino di paese terzo a norma della legislazione nazionale.</div>\n</div>"], [null, "<p class=\"norm\">L’avvio del procedimento di impugnazione non ha effetto sospensivo sul provvedimento di respingimento.</p>"], [null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<p class=\"norm\">Fatto salvo qualsiasi indennizzo concesso a norma del diritto nazionale, il cittadino di paese terzo interessato ha diritto a che lo Stato membro che ha proceduto al respingimento rettifichi i dati inseriti nell’EES o il timbro di ingresso annullato, o entrambi, e tutti gli altri annullamenti o aggiunte effettuati, se in esito al ricorso il provvedimento di respingimento risulta infondato.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Le guardie di frontiera vigilano affinché un cittadino di paese terzo oggetto di un provvedimento di respingimento non entri nel territorio dello Stato membro interessato.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Gli Stati membri raccolgono statistiche sul numero di persone respinte, i motivi del respingimento, la cittadinanza delle persone il cui ingresso è stato rifiutato e il tipo di frontiera (terrestre, aerea, marittima) alla quale sono state respinte e le trasmettono annualmente alla Commissione (Eurostat) conformemente al regolamento (CE) n. 862/2007 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">16</span>\n).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Le modalità del respingimento figurano nell’allegato V, parte A.</div>\n</div>"]]}, "15": {"label": "Articolo 15", "heading": "Personale e risorse per il controllo di frontiera", "anchor": "art_15", "frags": [[null, "<p class=\"norm\">Gli Stati membri predispongono personale e risorse appropriati e sufficienti per effettuare il controllo di frontiera alle frontiere esterne a norma degli articoli da 7 a 14 in modo da garantire un livello efficace, elevato ed uniforme di controllo alle frontiere esterne.</p>"]]}, "16": {"label": "Articolo 16", "heading": "Esecuzione del controllo", "anchor": "art_16", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il controllo di frontiera a norma degli articoli da 7 a 14 è eseguito dalle guardie di frontiera ai sensi delle disposizioni del presente regolamento e alla legislazione nazionale.</div>\n</div>"], [null, "<p class=\"norm\">Nell’esecuzione di tale controllo di frontiera le guardie di frontiera conservano il potere di avviare azioni penali conferito loro dalla legislazione nazionale e che esula dal campo di applicazione del presente regolamento.</p>"], [null, "<p class=\"norm\">Gli Stati membri assicurano che le guardie di frontiera siano professionisti specializzati e debitamente formati, tenendo conto della base comune per la formazione delle guardie di frontiera stabilita e sviluppata dall’Agenzia europea per la gestione della cooperazione operativa alle frontiere esterne degli Stati membri («l'Agenzia»), istituita con regolamento (CE) n. 2007/2004. I programmi comprendono una formazione specializzata ai fini dell'individuazione e della gestione di situazioni che coinvolgono persone vulnerabili quali minori non accompagnati e vittime della tratta di esseri umani. Gli Stati membri, con il sostegno dell'Agenzia, incoraggiano le guardie di frontiera ad apprendere le lingue necessarie per l'esercizio delle loro funzioni.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli Stati membri notificano alla Commissione l’elenco dei servizi nazionali competenti per il controllo di frontiera in base alla rispettiva legislazione nazionale, a norma dell’articolo 39.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Ai fini di un’esecuzione efficace del controllo di frontiera, ciascuno Stato membro garantisce una cooperazione stretta e permanente tra i servizi nazionali competenti per il controllo di frontiera.</div>\n</div>"]]}, "17": {"label": "Articolo 17", "heading": "Cooperazione tra gli Stati membri", "anchor": "art_17", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli Stati membri si prestano assistenza e assicurano tra loro una cooperazione stretta e permanente ai fini di un’esecuzione efficace del controllo di frontiera a norma degli articoli da 7 a 16. Essi si scambiano tutte le informazioni utili.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La cooperazione operativa tra Stati membri nella gestione delle frontiere esterne è coordinata dall’Agenzia.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Fatte salve le competenze dell’Agenzia, gli Stati membri possono continuare la cooperazione operativa con altri Stati membri e/o paesi terzi alle frontiere esterne, compreso lo scambio di ufficiali di collegamento, laddove tale cooperazione integri l’azione dell’Agenzia stessa.</div>\n</div>"], [null, "<p class=\"norm\">Gli Stati membri si astengono da qualsiasi attività che possa mettere a repentaglio il funzionamento dell’Agenzia o il raggiungimento dei suoi obiettivi.</p>"], [null, "<p class=\"norm\">Gli Stati membri riferiscono all’Agenzia su tale cooperazione operativa di cui al primo comma.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Gli Stati membri provvedono alla formazione sulle norme in materia di controllo di frontiera e sui diritti fondamentali. Al riguardo si tiene conto delle norme comuni di formazione definite e ulteriormente sviluppate dall’Agenzia.</div>\n</div>"]]}, "18": {"label": "Articolo 18", "heading": "Controllo congiunto", "anchor": "art_18", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli Stati membri che non applicano l’articolo 22 alle frontiere terrestri comuni possono, fino alla data di applicazione del suddetto articolo, effettuare un controllo congiunto di tali frontiere comuni, nel qual caso una persona può essere fermata una sola volta ai fini dell’effettuazione delle verifiche d’ingresso e d’uscita, fatta salva la responsabilità individuale degli Stati membri derivante dagli articoli da 7 a 14.</div>\n</div>"], [null, "<p class=\"norm\">A tal fine, gli Stati membri possono concludere tra loro accordi bilaterali.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli Stati membri informano la Commissione degli accordi conclusi a norma del paragrafo 1.</div>\n</div>"]]}, "19": {"label": "Articolo 19", "heading": "Norme specifiche relative ai vari tipi di frontiera e ai diversi mezzi di trasporto utilizzati per l’attraversamento delle frontiere esterne", "anchor": "art_19", "frags": [[null, "<p class=\"norm\">Le norme specifiche di cui all’allegato VI si applicano alla verifica effettuata nei diversi tipi di frontiera e sui diversi mezzi di trasporto utilizzati per l’attraversamento dei valichi di frontiera.</p>"], [null, "<p class=\"norm\">Tali norme specifiche possono comportare deroghe agli articoli 5 e 6 e agli articoli da 8 a 14.</p>"]]}, "20": {"label": "Articolo 20", "heading": "Norme specifiche relative alle verifiche su talune categorie di persone", "anchor": "art_20", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le norme specifiche di cui all’allegato VII si applicano alle verifiche relative alle seguenti categorie di persone:</p>\n<p class=\"modref\">\n▼M3\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">capi di Stato, capi di governo e membri dei governi nazionali, accompagnati dai consorti, e membri delle loro delegazioni ufficiali, e sovrani e altri membri di rilievo di una famiglia reale;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">piloti di aeromobili e altri membri dell’equipaggio;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">marittimi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">titolari di passaporti diplomatici, ufficiali o di servizio, nonché membri di organizzazioni internazionali;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">lavoratori transfrontalieri;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">minori;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">servizi di soccorso, polizia e vigili del fuoco e guardie di frontiera;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">lavoratori off-shore.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Tali norme specifiche possono comportare deroghe agli articoli 5 e 6 e agli articoli da 8 a 14.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli Stati membri notificano alla Commissione i modelli di tessere rilasciate dai loro ministeri degli Affari esteri ai membri accreditati delle missioni diplomatiche e delle rappresentanze consolari nonché alle loro famiglie, a norma dell’articolo 39.</div>\n</div>"]]}, "21": {"label": "Articolo 21", "heading": "Misure alle frontiere esterne e sostegno dell'Agenzia", "anchor": "art_21", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Qualora una relazione di valutazione, redatta ai sensi dell'articolo 14 del regolamento (UE) n. 1053/2013, individui gravi carenze nello svolgimento del controllo alle frontiere esterne e per garantire l'osservanza delle raccomandazioni di cui all'articolo 15 di detto regolamento, la Commissione può raccomandare, mediante un atto di esecuzione, che lo Stato membro valutato adotti misure specifiche, che possono comprendere una o entrambi delle seguenti opzioni:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">avvio dell'operazione di invio di squadre europee di guardie di frontiera conformemente alle disposizioni del regolamento (CE) n. 2007/2004;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">presentazione all'Agenzia, per un suo parere, dei suoi piani strategici basati su una valutazione dei rischi, comprese informazioni sull'invio di personale e delle attrezzature.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Tale atto di esecuzione è adottato secondo la procedura d'esame di cui all'articolo 38, paragrafo 2.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La Commissione informa regolarmente il comitato istituito a norma dell'articolo 38, paragrafo 1, in merito ai progressi compiuti nell'attuazione delle misure di cui al paragrafo 1 del presente articolo e del relativo effetto sulle carenze riscontrate.</div>\n</div>"], [null, "<p class=\"norm\">Essa ne informa altresì il Parlamento europeo e il Consiglio.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Qualora la relazione di valutazione di cui al paragrafo 1 abbia concluso che lo Stato membro valutato trascura gravemente i suoi obblighi e deve pertanto riferire in merito all'attuazione del pertinente piano d'azione entro tre mesi in conformità dell'articolo 16, paragrafo 4, del regolamento (UE) n. 1053/2013 e qualora, allo scadere di tale periodo di tre mesi, la Commissione constata che la situazione persiste, essa può, ove tutte le condizioni siano soddisfatte, attivare l'applicazione della procedura di cui all'articolo 29 del presente regolamento.</div>\n</div>"]]}, "21a": {"label": "Articolo 21 bis", "heading": "Restrizioni temporanee dei viaggi verso l’Unione", "anchor": "art_21a", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il presente articolo si applica alle emergenze di sanità pubblica su vasta scala.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il Consiglio, sulla base di una proposta della Commissione, può adottare un regolamento di esecuzione che prevede restrizioni temporanee dei viaggi verso gli Stati membri da applicare alle frontiere esterne.</div>\n</div>"], [null, "<p class=\"norm\">Le restrizioni temporanee di viaggio possono includere restrizioni temporanee all’ingresso negli Stati membri e altre misure temporanee di carattere sanitario che sono necessarie per la tutela della salute pubblica nello spazio senza controllo alle frontiere interne. Tali restrizioni temporanee di carattere sanitario possono comprendere test, quarantena e autoisolamento.</p>"], [null, "<p class=\"norm\">Le restrizioni temporanee di viaggio verso l’Unione sono proporzionate e non discriminatorie. Qualora uno Stato membro adotti restrizioni più rigorose di quelle stabilite nell’atto di esecuzione, tali restrizioni non hanno un impatto negativo sul funzionamento dello spazio senza controllo alle frontiere interne. Le restrizioni temporanee di carattere sanitario nei confronti dei beneficiari del diritto alla libera circolazione ai sensi del diritto dell’Unione sono sempre conformi alla direttiva 2004/38/CE.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Sono esentate dalle restrizioni all’ingresso, a prescindere dallo scopo del viaggio, le categorie di persone seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">beneficiari del diritto alla libera circolazione ai sensi del diritto dell’Unione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">cittadini di paesi terzi che siano soggiornanti di lungo periodo a norma della direttiva 2003/109/CE e persone che beneficiano del diritto di soggiorno in virtù di altri strumenti del diritto dell’UE o nazionale, tra cui i beneficiari di protezione internazionale o persone che siano in possesso di un visto nazionale per soggiorno di lunga durata, nonché i loro familiari.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Le categorie di persone elencate nell’allegato XI, parte A, sono esentate dalle restrizioni all’ingresso.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Qualsiasi categoria di persone elencata nell’allegato XI, parte B, è esentata dalle restrizioni all’ingresso ove tale categoria sia inclusa nel regolamento di esecuzione di cui al paragrafo 2.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il regolamento di esecuzione di cui al paragrafo 2 deve, a seconda dei casi:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">identificare, ove richiesto dalla natura dell’emergenza di sanità pubblica su vasta scala, le categorie di persone che effettuano viaggi essenziali elencate nell’allegato XI, parte B, da esentare dalle restrizioni all’ingresso;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">determinare le aree geografiche o i paesi terzi da cui i viaggi possano essere soggetti a restrizioni o esenti da restrizioni e stabilire una procedura per sottoporre a un riesame periodico la situazione di tali aree o paesi e delle restrizioni di viaggio imposte, sulla base di metodologia oggettiva e criteri oggettivi, tra cui in particolare la situazione epidemiologica;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">stabilire a quali condizioni i viaggi non essenziali possano essere soggetti a restrizioni o essere esentati da restrizioni, compresa la prova da esibire per l’esenzione e le condizioni relative alla durata e alla natura del soggiorno nelle aree o nei paesi di cui alla lettera b);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">fare riferimento a restrizioni minime temporanee di carattere sanitario cui possono essere soggette le persone di cui al paragrafo 3, lettere a) e b);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">in deroga ai paragrafi 4 e 5, stabilire a quali condizioni possano essere imposte restrizioni di viaggio alle persone che effettuano viaggi essenziali.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Le restrizioni all’ingresso negli Stati membri per le persone che effettuano viaggi essenziali sono imposte solo in via eccezionale, per un periodo di tempo strettamente limitato, fino a quando non sono disponibili informazioni sufficienti sulle emergenze di sanità pubblica su vasta scala di cui al paragrafo 1 o su una nuova variante di tali emergenze e finché il Consiglio, su proposta della Commissione, non avrà individuato e adottato restrizioni alternative di carattere sanitario, necessarie per proteggere la salute pubblica, da applicare a tali persone.</div>\n</div>"]]}, "22": {"label": "Articolo 22", "heading": "Attraversamento delle frontiere interne", "anchor": "art_22", "frags": [[null, "<p class=\"norm\">Le frontiere interne possono essere attraversate in qualunque punto senza che sia effettuata una verifica di frontiera sulle persone, indipendentemente dalla loro nazionalità.</p>"]]}, "23": {"label": "Articolo 23", "heading": "Verifiche all’interno del territorio", "anchor": "art_23", "frags": [[null, "<p class=\"norm\">L’assenza del controllo di frontiera alle frontiere interne non pregiudica:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’esercizio delle competenze di polizia o di altri pubblici poteri da parte delle autorità competenti degli Stati membri nei rispettivi territori, comprese le zone di frontiera interne, in forza della legislazione nazionale, nella misura in cui l’esercizio di detti poteri non sia di effetto equivalente alle verifiche di frontiera. L’esercizio di tali competenze può comprendere, se del caso, l’uso di tecnologie di monitoraggio e sorveglianza generalmente utilizzate nel territorio per far fronte a minacce alla sicurezza pubblica o all’ordine pubblico. L’esercizio da parte delle autorità competenti delle loro competenze non è considerato equivalente, in particolare, all’esercizio delle verifiche di frontiera quando le misure soddisfano ciascuna delle condizioni seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">non hanno come obiettivo il controllo di frontiera;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">si basano su informazioni di polizia generali o, se l’obiettivo è contenere il diffondersi di una malattia infettiva, su informazioni della sanità pubblica e sull’esperienza delle autorità competenti quanto a possibili minacce per la pubblica sicurezza e l’ordine pubblico e sono volte, in particolare, a:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">lottare contro la criminalità transfrontaliera;</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">ridurre l’immigrazione irregolare; oppure</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">contenere il diffondersi di una malattia infettiva con potenziale epidemico, quale identificata dal Centro europeo per la prevenzione e il controllo delle malattie;</div>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sono ideate ed eseguite in maniera chiaramente distinta dalle verifiche sistematiche sulle persone alle frontiere esterne, ivi compreso nei poli di trasporto o direttamente a bordo dei servizi di trasporto passeggeri e purché siano basate su una valutazione del rischio;</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la possibilità per le autorità competenti di uno Stato membro o per i vettori di far eseguire il controllo di sicurezza sulle persone nei poli di trasporto in conformità della legislazione di ciascuno Stato membro, sempreché tale controllo sia eseguito anche sulle persone che viaggiano all’interno di detto Stato membro;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la possibilità per uno Stato membro di prevedere nella legislazione nazionale l’obbligo di possedere o di portare con sé documenti d’identità;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la possibilità per uno Stato membro di prevedere nel diritto nazionale l’obbligo per i cittadini di paesi terzi di dichiarare la loro presenza sul suo territorio e l’obbligo per i gestori delle strutture che forniscono alloggio di provvedere che i cittadini di paesi terzi completino e firmino i moduli di registrazione, ad accezione dei coniugi o dei minorenni che li accompagnano o dei membri di un gruppo, ai sensi degli articoli 22 e 45, rispettivamente, della Convenzione di applicazione dell’Accordo di Schengen del 14 giugno 1985 tra i governi degli Stati dell’Unione economica Benelux, della Repubblica federale di Germania e della Repubblica francese relativo all’eliminazione graduale dei controlli alle frontiere comuni («convenzione di Schengen»).</p>\n</div>\n</div>"]]}, "23a": {"label": "Articolo 23 bis", "heading": "Procedura per il trasferimento di persone rintracciate nelle zone di frontiera interne", "anchor": "art_23a", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Fatto salvo l’articolo 22, il presente articolo stabilisce la procedura per il trasferimento di un cittadino di paese terzo rintracciato in zone di frontiera di cui all’articolo 23, ove ricorrano le condizioni seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il cittadino di paese terzo è rintracciato durante i controlli che coinvolgono le autorità competenti di entrambi gli Stati membri nel quadro della cooperazione bilaterale, che può comprendere, in particolare, pattugliamenti congiunti di polizia, a condizione che gli Stati membri abbiano convenuto di ricorrere a tale procedura nell’ambito di tale cooperazione bilaterale; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sussistono chiare indicazioni, sulla base di informazioni messe immediatamente a disposizione delle autorità che hanno rintracciato il cittadino di paese terzo, tra cui sue dichiarazioni e documenti di identità, viaggio o altri documenti trovati addosso al medesimo, o dei risultati di ricerche svolte nelle pertinenti banche dati nazionali e dell’Unione, che il cittadino di paese terzo sia arrivato direttamente da un altro Stato membro ed è sia accertato che il cittadino di paese terzo non ha il diritto di soggiornare nel territorio dello Stato membro in cui è arrivato.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">La procedura di cui ai paragrafi 1 e 2 non si applica ai richiedenti quali definiti all’articolo 3, punto 13), del regolamento (UE) 2024/1348 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">17</span>\n) o ai beneficiari quali definiti all’articolo 3, punto 4), del regolamento (UE) 2024/1347 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">18</span>\n).</p>"], [null, "<p class=\"norm\">In caso di trasferimento di un cittadino di paese terzo che è ritenuto essere un minore dallo Stato membro che provvede al trasferimento, detto Stato membro informa di tale presunzione lo Stato membro ricevente ed entrambi gli Stati membri provvedono affinché siano adottate tutte le misure nell’interesse superiore del minore e conformemente alle rispettive normative nazionali.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">In deroga all’articolo 6, paragrafo 1, della direttiva 2008/115/CE, le autorità competenti di uno Stato membro possono decidere, se sono soddisfatte le condizioni di cui al paragrafo 1, di trasferire immediatamente il cittadino di paese terzo interessato nello Stato membro di arrivo, secondo la procedura di cui all’allegato XII.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">I cittadini di paesi terzi rintracciati nelle zone di frontiera e trasferiti in virtù della procedura di cui al presente articolo hanno il diritto di presentare ricorso. I ricorsi avverso il provvedimento di trasferimento sono disciplinati conformemente alla legislazione nazionale dello Stato membro che provvede al trasferimento. A tali cittadini di paesi terzi è garantito un ricorso effettivo conformemente all’articolo 47 della Carta. A tali cittadini di paesi terzi sono altresì consegnate informazioni scritte da parte dello Stato membro che provvede al trasferimento riguardanti punti di contatto in grado di fornire informazioni su rappresentanti competenti ad agire per loro conto a norma della legislazione nazionale in una lingua che capiscono o che è ragionevole supporre possano capire. L’avvio del procedimento di impugnazione non ha effetto sospensivo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Se lo Stato membro che provvede al trasferimento esperisce la procedura di cui al paragrafo 2, lo Stato membro ricevente è tenuto a prendere tutti i provvedimenti del caso per accogliere il cittadino di paese terzo interessato secondo le procedure di cui all’allegato XII. Nello Stato membro ricevente si applicano tutte le pertinenti disposizioni della direttiva 2008/115/CE.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Gli Stati membri definiscono modalità pratiche nell’ambito dei rispettivi quadri di cooperazione bilaterale, anche allo scopo, di norma, di evitare il ricorso alla procedura di cui al paragrafo 2 del presente articolo, in particolare per quanto riguarda le sezioni delle frontiere interne in cui il controllo di frontiera è stato ripristinato o prorogato.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">La procedura di cui al presente articolo lascia impregiudicati gli accordi o le intese bilaterali esistenti di cui all’articolo 6, paragrafo 3, della direttiva 2008/115/CE.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">A decorrere dall'11 luglio 2025 e successivamente con cadenza annuale, gli Stati membri trasmettono alla Commissione i dati registrati a norma dell’allegato XII, parte A, punto 4.</div>\n</div>"]]}, "24": {"label": "Articolo 24", "heading": "Eliminazione degli ostacoli al traffico presso i valichi di frontiera stradali alle frontiere interne", "anchor": "art_24", "frags": [[null, "<p class=\"modref\">\n▼M7\n</p>"], [null, "<p class=\"norm\">Gli Stati membri eliminano tutti gli ostacoli allo scorrimento fluido del traffico presso i valichi di frontiera stradali alle frontiere interne, in particolare gli eventuali limiti di velocità non dettati esclusivamente da considerazioni in materia di sicurezza stradale o prescritti per l’uso delle tecnologie di cui all’articolo 23, lettera a).</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<p class=\"norm\">Al tempo stesso gli Stati membri sono pronti a predisporre strutture destinate alle verifiche, qualora siano ripristinati i controlli alle frontiere interne.</p>"]]}, "25": {"label": "Articolo 25", "heading": "Quadro generale per il ripristino temporaneo o la proroga del controllo di frontiera alle frontiere interne", "anchor": "art_25", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">In caso di minaccia grave per l’ordine pubblico o la sicurezza interna di uno Stato membro nello spazio senza controllo alle frontiere interne, detto Stato membro può in via eccezionale ripristinare il controllo di frontiera in tutte le parti o in parti specifiche delle sue frontiere interne.</div>\n</div>"], [null, "<p class=\"norm inline-element\">Una minaccia grave per l’ordine pubblico o la sicurezza interna può considerarsi derivare in particolare da:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">attentati o minacce di tipo terroristico, e minacce apportate da forme gravi di criminalità organizzata;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">emergenze di sanità pubblica su vasta scala;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una situazione eccezionale caratterizzata da spostamenti non autorizzati improvvisi e su vasta scala di cittadini di paesi terzi tra Stati membri, che mette a dura prova le risorse e le capacità complessive di autorità competenti ben preparate e che potrebbe mettere a rischio il funzionamento globale dello spazio senza controllo alle frontiere interne, come dimostrato dall’analisi delle informazioni e da tutti i dati disponibili, anche provenienti dalle agenzie dell’Unione competenti;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">eventi internazionali di ampia portata o alto profilo;</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il controllo di frontiera alle frontiere interne è comunque e sempre ripristinato solamente come misura di extrema ratio. L’estensione e la durata del ripristino temporaneo del controllo di frontiera non eccedono quanto strettamente necessario per rispondere alla minaccia grave individuata.</div>\n</div>"], [null, "<p class=\"norm\">Il controllo di frontiera può essere ripristinato o prorogato a norma degli articoli 25 <span class=\"italics\">bis</span> e 28 solo se lo Stato membro interessato ha stabilito che la misura è necessaria e proporzionata alla luce dei criteri di cui all’articolo 26, paragrafo 1, e, in caso di proroga del controllo, tenendo conto anche della valutazione del rischio di cui all’articolo 26, paragrafo 2. Il controllo di frontiera può essere ripristinato anche a norma dell’articolo 29 alla luce dei criteri di cui all’articolo 30.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Se la stessa grave minaccia perdura, il controllo di frontiera alle frontiere interne può essere prorogato conformemente agli articoli 25 <span class=\"italics\">bis</span> o 29 oppure, nel caso in cui la minaccia sia connessa a emergenze di sanità pubblica su vasta scala, all’articolo 28.</div>\n</div>"], [null, "<p class=\"norm\">La stessa grave minaccia è considerata perdurare se la giustificazione addotta dallo Stato membro per la proroga del controllo di frontiera è fondata sugli stessi motivi che avevano giustificato il ripristino iniziale del controllo di frontiera.</p>"]]}, "25a": {"label": "Articolo 25 bis", "heading": "Procedura per casi che richiedono un intervento a causa di eventi imprevedibili o prevedibili", "anchor": "art_25a", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Quando una minaccia grave per l’ordine pubblico o la sicurezza interna di uno Stato membro è imprevedibile e richiede un’azione immediata, lo Stato membro può, in via eccezionale, ripristinare immediatamente il controllo di frontiera alle frontiere interne.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Nel ripristinare il controllo di frontiera a norma del paragrafo 1 del presente articolo, lo Stato membro ne dà notifica al Parlamento europeo, al Consiglio, alla Commissione e agli altri Stati membri conformemente all’articolo 27, paragrafo 1.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Qualora uno Stato membro reintroduce il controllo di frontiera alle frontiere interne in conformità del paragrafo 1, il controllo di frontiera può perdurare per un periodo limitato non superiore a un mese. Se la minaccia grave per l’ordine pubblico o la sicurezza interna perdura più a lungo di detto periodo, lo Stato membro può prorogare il controllo di frontiera alle frontiere interne per altri periodi, fino ad una durata massima che non superi tre mesi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Quando una minaccia grave per l’ordine pubblico o la sicurezza interna è prevedibile in uno Stato membro, questi ne dà notifica al Parlamento europeo, al Consiglio, alla Commissione e agli altri Stati membri conformemente all’articolo 27, paragrafo 1, entro quattro settimane prima del ripristino previsto del controllo di frontiera, o il prima possibile se le circostanze che rendono necessario il ripristino del controllo di frontiera alle frontiere interne sono note meno di quattro settimane prima del ripristino previsto.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Qualora si applichi il paragrafo 4 del presente articolo e fatto salvo il paragrafo 6, il controllo di frontiera alle frontiere interne può essere ripristinato per massimo sei mesi. Se la minaccia grave per l’ordine pubblico o la sicurezza interna perdura oltre detto termine, lo Stato membro può prorogare il controllo di frontiera alle frontiere interne per periodi rinnovabili non superiori a sei mesi. Le eventuali proroghe devono essere notificate al Parlamento europeo, al Consiglio, alla Commissione e agli altri Stati membri conformemente all’articolo 27 e nei termini di cui al paragrafo 4 del presente articolo. Fatto salvo il paragrafo 6 del presente articolo, la durata massima del controllo di frontiera alle frontiere interne non è superiore a due anni.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Lo Stato membro che ritenga sussista una grave situazione eccezionale in relazione a una grave minaccia persistente che giustifichi il necessario mantenimento del controllo di frontiera alle frontiere interne oltre il periodo massimo di cui al paragrafo 5 del presente articolo notifica al Parlamento europeo, al Consiglio, alla Commissione e agli altri Stati membri la sua intenzione di prorogare il controllo alle frontiere interne, almeno quattro settimane prima della proroga prevista, per un periodo supplementare che non superi i sei mesi. Tale notifica deve essere eseguita almeno quattro settimane prima della proroga prevista, tenendo conto del parere emesso dalla Commissione a norma dell’articolo 27 <span class=\"italics\">bis</span>, paragrafo 3, include una valutazione del rischio di cui all’articolo 26, paragrafo 2, che:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">motiva il perdurare della minaccia per l’ordine pubblico o la sicurezza interna;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dimostra che le misure alternative per rispondere alla minaccia sono ritenute inefficaci o si sono rivelate tali al momento della notifica;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">presenta le misure di attenuazione prese in considerazione per accompagnare il controllo di frontiera alle frontiere interne;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">include, ove opportuno, una presentazione dei mezzi, delle azioni, delle condizioni e del calendario contemplati per la revoca del controllo di frontiera alle frontiere interne.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Entro tre mesi dalla notifica di cui al primo comma, la Commissione emette un nuovo parere sulla necessità e sulla proporzionalità della proroga del controllo di frontiera alle frontiere interne. Dopo il ricevimento di tale notifica, la Commissione può stabilire di propria iniziativa o stabilisce su richiesta dello Stato membro direttamente coinvolto un processo di consultazione, conformemente all’articolo 27 <span class=\"italics\">bis</span>, paragrafo 1.</p>"], [null, "<p class=\"norm\">Se, in una grave circostanza eccezionale, la continuazione della necessità del controllo di frontiera alle frontiere interne è confermata a seguito della procedura di cui al presente paragrafo e il periodo supplementare di sei mesi di cui al primo comma non è sufficiente a garantire la disponibilità di misure alternative efficaci per far fronte alla minaccia persistente, uno Stato membro può decidere di prorogare il controllo di frontiera alle frontiere interne per un ulteriore e definitivo periodo massimo di sei mesi, in linea con la valutazione del rischio di cui al secondo comma. Se decide in tal senso, lo Stato membro notifica senza ritardo alla Commissione la sua intenzione di prorogare il controllo di frontiera alle frontiere interne. La Commissione adotta senza ritardo una raccomandazione sulla compatibilità di tale proroga finale con i trattati, in particolare con i principi di necessità e proporzionalità. Tale raccomandazione individua inoltre, se del caso con altri Stati membri, le efficaci misure compensative da attuare.</p>"]]}, "26": {"label": "Articolo 26", "heading": "Criteri per il ripristino temporaneo e la proroga del controllo di frontiera alle frontiere interne", "anchor": "art_26", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Per appurare se il ripristino del controllo di frontiera alle frontiere interne sia necessario e proporzionato a norma dell’articolo 25, paragrafo 2, uno Stato membro valuta in particolare:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se ripristinare il controllo di frontiera alle frontiere interne sia una misura opportuna, vista la natura della minaccia grave individuata, e in particolare fino a che punto tale misura può rispondere in modo adeguato alla minaccia per l’ordine pubblico o la sicurezza interna e se gli obiettivi perseguiti da tale ripristino possano essere raggiunti attraverso:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il ricorso a misure alternative, come verifiche proporzionate svolte nel contesto di controlli all’interno del territorio come previsto all’articolo 23, lettera a);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il ricorso alla procedura di cui all’articolo 23 <span class=\"italics\">bis</span>;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">altre forme di cooperazione di polizia previste dal diritto dell’Unione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iv) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">misure comuni in materia di restrizioni temporanee di viaggio verso gli Stati membri di cui all’articolo 21 <span class=\"italics\">bis</span>, paragrafo 2;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’impatto probabile di una tale misura:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sulla circolazione delle persone all’interno dello spazio senza controllo alle frontiere interne; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sul funzionamento delle regioni transfrontaliere, considerati i forti legami sociali ed economici che le uniscono.</p>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Se il controllo alle frontiere interne è in vigore da sei mesi a norma dell’articolo 25 <span class=\"italics\">bis</span>, paragrafo 5, lo Stato membro interessato effettua una valutazione del rischio che, oltre agli elementi di cui all’articolo 27, paragrafi 2 e 3, comprende anche una nuova valutazione dei criteri di cui al paragrafo 1 del presente articolo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">In caso di ripristino o proroga del controllo di frontiera alle frontiere interne, gli Stati membri interessati predispongono opportune misure di accompagnamento che ne attenuino le ripercussioni sulle persone e sul trasporto di merci, prestando particolare attenzione ai forti legami sociali ed economici tra le regioni transfrontaliere e alle persone che effettuano viaggi essenziali.</div>\n</div>"]]}, "27": {"label": "Articolo 27", "heading": "Notifica del ripristino temporaneo o proroga del controllo di frontiera alle frontiere interne e valutazione del rischio", "anchor": "art_27", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le notifiche del ripristino o della proroga del controllo di frontiera alle frontiere interne inviate dagli Stati membri contengono le informazioni seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i motivi del ripristino o della proroga, compresi tutti i dati pertinenti relativi agli eventi che costituiscono una minaccia grave per il proprio ordine pubblico o la propria sicurezza interna;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’estensione del ripristino o della proroga, precisando la parte o le parti delle frontiere interne alle quali sarà ripristinato o prorogato il controllo di frontiera;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la denominazione dei valichi di frontiera autorizzati;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la data e la durata del ripristino o della proroga;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la valutazione della necessità e della proporzionalità alla luce dei criteri di cui all’articolo 26, paragrafo 1, e paragrafo 2 in caso di proroga;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">eventualmente, le misure che devono essere adottate da altri Stati membri.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">La notifica può essere presentata anche congiuntamente da due o più Stati membri.</p>"], [null, "<p class=\"norm\">Gli Stati membri trasmettono la notifica usando il modello stabilito dalla Commissione a norma del paragrafo 6.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Nei casi in cui il controllo di frontiera sia in atto da sei mesi conformemente all’articolo 25 <span class=\"italics\">bis</span>, paragrafo 5, ogni successiva notifica di proroga di detto controllo deve includere una valutazione del rischio. La valutazione del rischio presenta la portata e l’evoluzione prevista della minaccia grave, indicando in particolare quanto a lungo si prevede che possa perdurare e quali potrebbero essere le sezioni di frontiera interna interessate, e informazioni sulle misure di coordinamento decise con gli altri Stati membri coinvolti anche solo potenzialmente dal controllo di frontiera alle frontiere interne.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Se gli Stati membri ripristinano o prorogano il controllo di frontiera a causa di una situazione di cui all’articolo 25, paragrafo 1, lettera c), la valutazione prescritta dal paragrafo 1, lettera e), del presente articolo include anche una valutazione del rischio e informazioni sugli spostamenti non autorizzati improvvisi e su vasta scala, comprese le informazioni pervenute dalle agenzie competenti dell’Unione nell’ambito dei rispettivi mandati, e l’analisi dei dati dei pertinenti sistemi di informazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Su richiesta della Commissione lo Stato membro interessato fornisce ogni complemento di informazione, anche sulle misure di coordinamento con gli Stati membri coinvolti dalla prevista proroga del controllo di frontiera alle frontiere interne, e altre informazioni necessarie per valutare l’eventuale ricorso alle misure di cui agli articoli 23 e 23 <span class=\"italics\">bis</span>.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Gli Stati membri non sono tenuti a fornire tutte le informazioni di cui ai paragrafi da 1 a 4 del presente articolo nei casi giustificati da motivi di pubblica sicurezza, tenuto conto della riservatezza delle indagini in corso. Gli Stati membri che presentano una notifica ai sensi del paragrafo 1 o 2 possono, se necessario e in conformità della legge nazionale, decidere di classificare, in tutto o in parte, le informazioni notificate, in particolare le valutazioni del rischio. Tale classificazione non preclude l’accesso alle informazioni, attraverso opportuni canali sicuri, agli altri Stati membri interessati dal ripristino temporaneo del controllo di frontiera alle frontiere interne. Tale classificazione non preclude la trasmissione delle informazioni al Parlamento europeo da parte degli Stati membri. La trasmissione e il trattamento delle informazioni e dei documenti trasmessi al Parlamento europeo a norma del presente articolo non comprendono le valutazioni del rischio di cui al paragrafo 2 e rispettano le norme relative alla trasmissione e al trattamento delle informazioni classificate.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">La Commissione adotta un atto di esecuzione che stabilisca il modello di cui al paragrafo 1, terzo comma, del presente articolo, e lo rende disponibile online. Tale atto di esecuzione è adottato secondo la procedura d’esame di cui all’articolo 38, paragrafo 2.</div>\n</div>"]]}, "27a": {"label": "Articolo 27 bis", "heading": "Consultazione tra Stati membri e parere della Commissione", "anchor": "art_27a", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ricevute le notifiche presentate a norma dell’articolo 27, paragrafo 1, la Commissione può stabilire di sua iniziativa, o stabilisce su richiesta di uno Stato membro direttamente coinvolto dal controllo di frontiera alle frontiere interne, un processo di consultazione comprendente riunioni congiunte tra lo Stato membro che prevede di ripristinare o prorogare il controllo di frontiera alle frontiere interne e gli altri Stati membri, specialmente quelli direttamente coinvolti da tali misure, e le agenzie dell’Unione competenti.</div>\n</div>"], [null, "<p class=\"norm\">La consultazione ha lo scopo di esaminare in particolare la minaccia per l’ordine pubblico o la sicurezza interna, la necessità e la proporzionalità del previsto ripristino del controllo di frontiera alle frontiere interne tenendo conto dell’opportunità di misure alternative, l’impatto di tale controllo di frontiera qualora sia già stato ripristinato, e le modalità per garantire l’attuazione della cooperazione reciproca tra gli Stati membri in relazione al ripristino del controllo di frontiera alle frontiere interne.</p>"], [null, "<p class=\"norm\">Lo Stato membro che prevede di ripristinare o prorogare il controllo di frontiera alle frontiere interne tiene in considerazione i risultati di tale consultazione nel decidere se ripristinare o prorogare il controllo di frontiera alle frontiere interne e nell’eseguire detto controllo.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Ricevute le notifiche presentate in relazione al ripristino o alla proroga del controllo di frontiera alle frontiere interne, la Commissione emette un parere, o uno Stato membro può emettere un parere, fatto salvo l’articolo 72 TFUE, se, sulla base delle informazioni contenute nella notifica e nella valutazione del rischio, a seconda dei casi, o di eventuali complementi di informazione ricevuti, nutre preoccupazione sulla necessità o sulla proporzionalità del previsto ripristino o della prevista proroga del controllo di frontiera alle frontiere interne.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Ricevute le notifiche presentate in relazione alla proroga del controllo di frontiera alle frontiere interne ai sensi dell’articolo 25 <span class=\"italics\">bis</span>, paragrafo 4, risultante nel mantenimento de controllo di frontiera per un totale di dodici mesi, la Commissione emette un parere sulla necessità e sulla proporzionalità di detto controllo di frontiera.</div>\n</div>"], [null, "<p class=\"norm inline-element\">Il parere della Commissione include almeno:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una valutazione della conformità del ripristino o della proroga del controllo di frontiera alle frontiere interne ai principi di necessità e proporzionalità;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una valutazione volta a stabilire se siano state esaminate a sufficienza misure alternative per rispondere alla minaccia grave.</p>\n</div>\n</div>"], [null, "<p class=\"norm\">Qualora il ripristino del controllo di frontiera alle frontiere interne sia stato valutato e sia stato ritenuto conforme ai principi di necessità e proporzionalità, il parere contiene, se del caso, raccomandazioni sul miglioramento della cooperazione tra gli Stati membri al fine di limitare l’impatto del controllo di frontiera alle frontiere interne e contribuire a ridurre la minaccia persistente.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Quando è emesso il parere di cui al paragrafo 2 o 3, la Commissione stabilisce un processo di consultazione, a norma del paragrafo 1, per discutere del parere con gli Stati membri.</div>\n</div>"]]}, "28": {"label": "Articolo 28", "heading": "Meccanismo specifico in caso di emergenza di sanità pubblica su vasta scala che mette a rischio il funzionamento globale dello spazio senza controllo alle frontiere interne", "anchor": "art_28", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ove accerti che esiste un’ emergenza di sanità pubblica su vasta scala che colpisce diversi Stati membri mettendo a rischio il funzionamento globale dello spazio senza controllo alle frontiere interne, la Commissione può presentare al Consiglio una proposta di decisione di esecuzione che autorizza gli Stati membri a ripristinare il controllo di frontiera, comprese eventuali opportune misure di attenuazione da istituirsi a livello nazionale e dell’Unione, se le misure disponibili di cui agli articoli 21 <span class=\"italics\">bis</span> e 23 non sono sufficienti per far fronte all’emergenza di sanità pubblica su larga scala. Gli Stati membri possono chiedere alla Commissione di presentare una tale proposta al Consiglio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La decisione di esecuzione del Consiglio di cui al paragrafo 1 autorizza una durata massima di sei mesi, rinnovabile su proposta della Commissione per ulteriori periodi di massimo sei mesi ciascuno finché perdura l’emergenza di sanità pubblica su vasta scala, alla luce del riesame di cui al paragrafo 4.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Se gli Stati membri ripristinano o prorogano il controllo di frontiera a causa dell’emergenza di sanità pubblica su vasta scala di cui al paragrafo 1, detto controllo di frontiera deve basarsi, a decorre dall’entrata in vigore della decisione di esecuzione del Consiglio di cui al paragrafo 1, sulla decisione medesima.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La Commissione riesamina regolarmente l’evoluzione dell’emergenza di sanità pubblica su vasta scala di cui al paragrafo 1e l’impatto delle misure adottate conformemente alla decisione di esecuzione del Consiglio di cui a tale paragrafo, per valutare se tali misure rimangono giustificate o, altrimenti, proporre la revoca del controllo di frontiera alle frontiere interne quanto prima.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Gli Stati membri notificano immediatamente al Parlamento europeo, al Consiglio, alla Commissione e agli Stati membri il ripristino del controllo di frontiera alle frontiere interne conformemente alla decisione di cui al paragrafo 1.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Gli Stati membri possono adottare altre misure di cui all’articolo 23 per limitare la portata del controllo di frontiera alle frontiere interne. La Commissione tiene conto di tali misure nel riesame di cui al paragrafo 4 del presente articolo.</div>\n</div>"]]}, "29": {"label": "Articolo 29", "heading": "Procedura specifica in caso di circostanze eccezionali che mettono a rischio il funzionamento globale dello spazio senza controllo alle frontiere interne", "anchor": "art_29", "frags": [[null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">In circostanze eccezionali in cui il funzionamento globale dello spazio senza controllo alle frontiere interne è messo a rischio a seguito di carenze gravi e persistenti nel controllo di frontiera alle frontiere esterne ai sensi dell'articolo 21 del presente regolamento oppure in conseguenza della mancata conformità di uno Stato membro alla decisione del Consiglio di cui all'articolo 19, paragrafo 1, del regolamento (UE) 2016/1624 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">19</span>\n), e nella misura in cui tali circostanze costituiscono una minaccia grave per l'ordine pubblico o la sicurezza interna nello spazio senza controllo alle frontiere interne o su parti dello stesso, il controllo di frontiera alle frontiere interne può essere ripristinato in conformità del paragrafo 2 del presente articolo per una durata massima di sei mesi. Tale periodo può essere prorogato non più di tre volte, per ulteriori sei mesi al massimo, se le circostanze eccezionali perdurano.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il Consiglio, allorché tutte le altre misure, in particolare quelle di cui all'articolo 21, paragrafo 1, non hanno consentito di ridurre efficacemente la grave minaccia individuata, raccomanda a uno o più Stati membri, come <span class=\"italics\">extrema ratio</span> e come misura volta a proteggere gli interessi comuni nello spazio senza controllo alle frontiere interne, di decidere di ripristinare il controllo di frontiera in tutte le rispettive frontiere interne o in parti specifiche delle stesse. La raccomandazione del Consiglio si basa su una proposta della Commissione. Gli Stati membri possono chiedere alla Commissione di presentare una tale proposta di raccomandazione al Consiglio.</div>\n</div>"], [null, "<p class=\"norm\">Nella sua raccomandazione, il Consiglio indica almeno le informazioni di cui all'articolo 27, paragrafo 1, lettere da a) a e).</p>"], [null, "<p class=\"norm\">Il Consiglio può raccomandare una proroga secondo le condizioni e la procedura di cui al presente articolo.</p>"], [null, "<p class=\"norm\">Prima che uno Stato membro ripristini il controllo di frontiera in tutte le sue frontiere interne o in parti specifiche delle stesse ai sensi del presente paragrafo, esso ne informa gli altri Stati membri, il Parlamento europeo e la Commissione.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Qualora la raccomandazione di cui al paragrafo 2 non sia attuata da uno Stato membro, quest'ultimo informa immediatamente la Commissione per iscritto dei propri motivi.</div>\n</div>"], [null, "<p class=\"norm\">In tal caso la Commissione presenta al Parlamento europeo e al Consiglio una relazione che valuta i motivi indicati dallo Stato membro interessato e le conseguenze per quanto riguarda la protezione degli interessi comuni nello spazio senza controllo alle frontiere interne.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Per motivi di urgenza debitamente giustificati e connessi a situazioni in cui le circostanze che rendono necessaria la proroga del controllo di frontiera alle frontiere interne, conformemente al paragrafo 2, sono note meno di dieci giorni prima della fine del periodo di ripristino precedente, la Commissione può adottare le eventuali raccomandazioni necessarie mediante atti di esecuzione immediatamente applicabili ai sensi della procedura di cui all'articolo 38, paragrafo 3. Entro quattordici giorni dall'adozione di tali raccomandazioni, la Commissione presenta al Consiglio una proposta di raccomandazione in conformità del paragrafo 2 del presente articolo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Il presente articolo lascia impregiudicate le misure che gli Stati membri possono adottare in caso di minaccia grave per l'ordine pubblico o la sicurezza interna a norma degli articoli 25, 27 e 28.</div>\n</div>"]]}, "30": {"label": "Articolo 30", "heading": "Criteri per il ripristino temporaneo del controllo di frontiera alle frontiere interne in caso di circostanze eccezionali che mettono a rischio il funzionamento globale dello spazio senza controllo alle frontiere interne", "anchor": "art_30", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Allorché il Consiglio raccomanda come <span class=\"italics\">extrema ratio</span> in conformità dell'articolo 29, paragrafo 2, il ripristino temporaneo del controllo di frontiera in una o più frontiere interne o in parti delle stesse, esso valuta in quale misura tale provvedimento possa costituire una risposta adeguata alla minaccia per l'ordine pubblico o la sicurezza interna nello spazio senza controllo alle frontiere interne e valuta la proporzionalità del provvedimento rispetto a tale minaccia. Tale valutazione si basa sulle informazioni dettagliate fornite dallo Stato membro o dagli Stati membri interessati e dalla Commissione e su ogni altra informazione pertinente, comprese le eventuali informazioni ottenute ai sensi del paragrafo 2 del presente articolo. Nell'effettuare tale valutazione si tiene conto, in particolare, delle seguenti considerazioni:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la disponibilità di misure di sostegno tecnico o finanziario che potrebbero essere o che sono state disposte a livello nazionale o di Unione, o ad entrambi i livelli, compresa l’assistenza di organi o organismi dell’Unione come l'Agenzia, l'Ufficio europeo di sostegno per l'asilo, istituito dal regolamento (UE) n. 439/2010 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">20</span>\n) o l'Ufficio europeo di polizia (Europol), istituito dalla decisione 2009/371/GAI, e la misura in cui tali azioni possano costituire una risposta adeguata alle minacce per l’ordine pubblico o la sicurezza interna nello spazio senza controllo alle frontiere interne;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’impatto attuale e probabile per il futuro delle carenze gravi nel controllo alle frontiere esterne individuate dalle relazioni di valutazione adottate ai sensi del regolamento (UE) n. 1053/2013 e la misura in cui tali carenze gravi costituiscano una minaccia grave per l'ordine pubblico o la sicurezza interna nello spazio senza controllo alle frontiere interne;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’impatto probabile del ripristino del controllo di frontiera alle frontiere interne sulla libera circolazione delle persone all’interno dello spazio senza controllo alle frontiere interne.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Prima di adottare una proposta di raccomandazione del Consiglio ai sensi dell'articolo 29, paragrafo 2, la Commissione può:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">chiedere agli Stati membri, all'Agenzia, a Europol o ad altri organi o organismi dell'Unione di fornirle ulteriori informazioni;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">effettuare visite in loco, con il sostegno di esperti degli Stati membri e dell'Agenzia, di Europol o di qualunque altro organo o organismo dell'Unione competente, per ottenere o verificare informazioni rilevanti ai fini della detta raccomandazione.</p>\n</div>\n</div>\n</div>\n</div>"]]}, "31": {"label": "Articolo 31", "heading": "Informazione del Parlamento europeo e al Consiglio", "anchor": "art_31", "frags": [[null, "<p class=\"norm\">La Commissione e lo Stato membro o gli Stati membri interessati informano quanto prima il Parlamento europeo e il Consiglio di qualunque motivo che possa determinare l'applicazione dell'articolo 21 e degli articoli da 25 a 30.</p>"]]}, "32": {"label": "Articolo 32", "heading": "Disposizioni in caso di ripristino del controllo di frontiera alle frontiere interne", "anchor": "art_32", "frags": [[null, "<p class=\"norm\">In caso di ripristino del controllo di frontiera alle frontiere interne, si applicano <span class=\"italics\">mutatis mutandis</span> le pertinenti disposizioni del titolo II.</p>"]]}, "33": {"label": "Articolo 33", "heading": "Relazione sul ripristino del controllo di frontiera alle frontiere interne", "anchor": "art_33", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Entro quattro settimane dalla soppressione del controllo di frontiera alle frontiere interne, gli Stati membri che hanno effettuato detto controllo presentano al Parlamento europeo, al Consiglio e alla Commissione una relazione sul ripristino e, se applicabile, sulla proroga del controllo di frontiera alle frontiere interne.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Fatto salvo il paragrafo 1, in caso di proroga del controllo di frontiera di cui all’articolo 25 <span class=\"italics\">bis</span>, paragrafo 5, lo Stato membro interessato presenta una relazione allo scadere di 12 mesi e successivamente dopo 12 mesi, se il controllo di frontiera è mantenuto in via eccezionale.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La relazione illustra in particolare la valutazione iniziale e di follow-up della necessità e della proporzionalità del controllo di frontiera, l’osservanza dei criteri di cui all’articolo 26, lo svolgimento delle verifiche, la cooperazione pratica con gli Stati membri confinanti, le conseguenti ripercussioni sulla libera circolazione delle persone, in particolare nelle regioni transfrontaliere, l’efficacia del ripristino del controllo di frontiera alle frontiere interne, compresa una valutazione ex post della necessità e della proporzionalità del ripristino del controllo di frontiera.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La Commissione adotta un atto di esecuzione che stabilisca un modello uniforme di relazione e lo rende disponibile online. Tale atto di esecuzione è adottato secondo la procedura d’esame di cui all’articolo 38, paragrafo 2.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">La Commissione può esprimere un parere sulla valutazione ex post del ripristino temporaneo del controllo di frontiera a una o più frontiere interne o in parti delle stesse.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Almeno una volta all’anno la Commissione riferisce al Parlamento europeo e al Consiglio sul funzionamento dello spazio senza controllo alle frontiere interne. La Commissione può inoltre discutere separatamente della relazione sullo stato di Schengen con il Parlamento europeo e il Consiglio. La relazione contiene un elenco di tutte le decisioni di ripristino del controllo di frontiera alle frontiere interne adottate nell’anno di riferimento, nonché le azioni adottate dalla Commissione in merito al ripristino del controllo di frontiera alle frontiere interne. La relazione presta particolare attenzione al controllo di frontiera in vigore da oltre dodici mesi. Essa include anche una valutazione della necessità e della proporzionalità del ripristino e delle proroghe del controllo di frontiera nel periodo di riferimento come pure informazioni sulle tendenze all’interno dello spazio senza controllo alle frontiere interne nell’ottica degli spostamenti non autorizzati di cittadini di paesi terzi, tenendo conto delle informazioni messe a disposizione dalle agenzie dell’Unione competenti e dell’analisi dei dati dei pertinenti sistemi di informazione.</div>\n</div>"]]}, "34": {"label": "Articolo 34", "heading": "Informazione del pubblico", "anchor": "art_34", "frags": [[null, "<p class=\"norm\">La Commissione e lo Stato membro interessato informano in maniera coordinata il pubblico di qualunque decisione di ripristinare il controllo di frontiera alle frontiere interne e indicano, in particolare, le date in cui tale misura ha inizio e fine, salvo che lo impediscano imprescindibili motivi di sicurezza.</p>"]]}, "35": {"label": "Articolo 35", "heading": "Riservatezza", "anchor": "art_35", "frags": [[null, "<p class=\"norm\">Su richiesta dello Stato membro interessato, gli altri Stati membri, il Parlamento europeo e la Commissione rispettano il carattere riservato delle informazioni fornite nell’ambito del ripristino e della proroga del controllo di frontiera, nonché della relazione redatta a norma dell’articolo 33.</p>"]]}, "36": {"label": "Articolo 36", "heading": "Modifiche degli allegati", "anchor": "art_36", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all’articolo 37 riguardo alle modifiche degli allegati III, IV e VIII.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all’articolo 37 al fine di integrare il presente regolamento inserendo nell’allegato XI, parte B, le categorie di persone che effettuano viaggi essenziali.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Ove sussistano motivi imperativi di urgenza, in casi debitamente giustificati in considerazione della natura dell’emergenza di sanità pubblica su vasta scala, agli atti delegati adottati in virtù del paragrafo 2 del presente articolo si applica la procedura di cui all’articolo 37 <span class=\"italics\">bis</span>.</div>\n</div>"]]}, "37": {"label": "Articolo 37", "heading": "Esercizio della delega", "anchor": "art_37", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il potere di adottare atti delegati è conferito alla Commissione alle condizioni stabilite nel presente articolo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il potere di adottare atti delegati di cui all'articolo 13, paragrafo 5, e all'articolo 36 è conferito alla Commissione per un periodo indeterminato.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La delega di cui all'articolo 13, paragrafo 5, e all'articolo 36 può essere revocata in qualsiasi momento dal Parlamento europeo o dal Consiglio. La decisione di revoca pone fine alla delega dei poteri ivi specificata. Gli effetti della decisione decorrono dal giorno successivo alla pubblicazione della decisione nella Gazzetta ufficiale dell'Unione europea o da una data successiva ivi specificata. Essa non pregiudica la validità degli atti delegati già in vigore.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Non appena adotta un atto delegato, la Commissione ne dà contestualmente notifica al Parlamento europeo e al Consiglio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">L'atto delegato adottato ai sensi dell'articolo 13, paragrafo 5, e dell'articolo 36 entra in vigore solo se né il Parlamento europeo né il Consiglio hanno sollevato obiezioni entro il termine di due mesi dalla data in cui esso è stato loro notificato o se, prima della scadenza di tale termine, sia il Parlamento europeo che il Consiglio hanno informato la Commissione che non intendono sollevare obiezioni. Tale termine è prorogato di due mesi su iniziativa del Parlamento europeo o del Consiglio.</div>\n</div>"]]}, "37a": {"label": "Articolo 37 bis", "heading": "Procedura d’urgenza", "anchor": "art_37a", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli atti delegati adottati ai sensi del presente articolo entrano in vigore immediatamente e si applicano finché non siano sollevate obiezioni conformemente al paragrafo 2. La notifica di un atto delegato al Parlamento europeo e al Consiglio illustra i motivi del ricorso alla procedura d’urgenza.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il Parlamento europeo o il Consiglio possono sollevare obiezioni a un atto delegato secondo la procedura di cui all’articolo 37, paragrafo 5. In tal caso, la Commissione abroga l’atto immediatamente a seguito della notifica della decisione con la quale il Parlamento europeo o il Consiglio hanno sollevato obiezioni.</div>\n</div>"]]}, "38": {"label": "Articolo 38", "heading": "Procedura di comitato", "anchor": "art_38", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La Commissione è assistita da un comitato. Esso è un comitato ai sensi del regolamento (UE) n. 182/2011.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Nei casi in cui è fatto riferimento al presente paragrafo, si applica l’articolo 5 del regolamento (UE) n. 182/2011. Qualora il comitato non esprima alcun parere, la Commissione non adotta il progetto di atto di esecuzione e si applica l’articolo 5, paragrafo 4, terzo comma, del regolamento (UE) n. 182/2011.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Nei casi in cui è fatto riferimento al presente paragrafo, si applica l’articolo 8 del regolamento (UE) n. 182/2011, in combinato disposto con il suo articolo 5.</div>\n</div>"]]}, "39": {"label": "Articolo 39", "heading": "Comunicazioni", "anchor": "art_39", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Gli Stati membri comunicano alla Commissione:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'elenco dei permessi di soggiorno, distinguendo fra quelli contemplati dall'articolo 2, punto 16, lettera a) e quelli contemplati dall'articolo 2, punto 16, lettera b) e corredati di un facsimile per i permessi di cui all'articolo 2, punto 16, lettera b). Le carte di soggiorno rilasciate conformemente alla direttiva 2004/38/CE sono appositamente specificate come tali e per le carte di soggiorno che non sono state rilasciate secondo il modello uniforme di cui al regolamento (CE) n. 1030/2002 sono forniti dei facsimile;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’elenco dei rispettivi valichi di frontiera;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli importi di riferimento richiesti per l’attraversamento delle loro frontiere esterne fissati ogni anno dalle autorità nazionali;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’elenco dei servizi nazionali competenti per il controllo di frontiera;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il facsimile dei modelli di tessere rilasciate dai ministeri degli Affari esteri;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le eccezioni alle norme concernenti l'attraversamento delle frontiere esterne di cui all'articolo 5, paragrafo 2, lettera a);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le statistiche di cui all'articolo 11, paragrafo 3;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M7\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le zone considerate regioni transfrontaliere e eventuali successive modifiche.</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La Commissione mette a disposizione degli Stati membri e del pubblico le informazioni che le sono state comunicate a norma del paragrafo 1, pubblicandole nella <span class=\"italics\">Gazzetta ufficiale dell’Unione europea</span>, serie C, e con ogni altro mezzo appropriato.</div>\n</div>"]]}, "40": {"label": "Articolo 40", "heading": "Traffico frontaliero locale", "anchor": "art_40", "frags": [[null, "<p class=\"norm\">Il presente regolamento lascia impregiudicate le norme dell'Unione e gli accordi bilaterali vigenti in materia di traffico frontaliero locale.</p>"]]}, "41": {"label": "Articolo 41", "heading": "Ceuta e Melilla", "anchor": "art_41", "frags": [[null, "<p class=\"norm\">Le disposizioni del presente regolamento non pregiudicano il regime specifico che si applica a Ceuta e Melilla, quale definito nella dichiarazione del Regno di Spagna relativa alle città di Ceuta e Melilla di cui all’atto finale dell’accordo di adesione del Regno di Spagna alla convenzione di applicazione dell’accordo di Schengen del 14 giugno 1985 (\n<span class=\"superscript\">21</span>\n).</p>"]]}, "42": {"label": "Articolo 42", "heading": "Notifica di informazioni da parte degli Stati membri", "anchor": "art_42", "frags": [[null, "<p class=\"norm\">Gli Stati membri notificano alla Commissione le loro disposizioni interne relative all’articolo 23, lettere c) e d), le sanzioni di cui all’articolo 5, paragrafo 3, e gli accordi bilaterali autorizzati dal presente regolamento. Le ulteriori modifiche di tali disposizioni sono notificate entro cinque giorni lavorativi.</p>"], [null, "<p class=\"norm\">Le informazioni comunicate dagli Stati membri sono pubblicate nella <span class=\"italics\">Gazzetta ufficiale dell’Unione europea</span>, serie C.</p>"]]}, "42a": {"label": "Articolo 42 bis", "heading": "Misure transitorie per gli Stati membri in cui l’EES non è ancora operativo", "anchor": "art_42a", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">I documenti di viaggio dei cittadini di paesi terzi che attraversano le frontiere degli Stati membri di cui all’articolo 66, paragrafo 3, del regolamento (UE) 2017/2226 sono timbrati sistematicamente all’ingresso e all’uscita.</div>\n</div>"], [null, "<p class=\"norm\">I documenti di viaggio dei cittadini di paesi terzi di cui all’articolo 6 <span class=\"italics\">bis</span>, paragrafo 1, lettere b) e c), del presente regolamento che attraversano le frontiere degli Stati membri di cui all’articolo 66, paragrafo 3, del regolamento (UE) 2017/2226 sono timbrati all’ingresso e all’uscita.</p>"], [null, "<p class=\"norm\">Tali obblighi di apposizione del timbro si applicano anche in caso di snellimento delle verifiche di frontiera in conformità dell’articolo 9 del presente regolamento.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">In deroga al paragrafo 1 del presente articolo, non si appongono timbri sui documenti di viaggio dei cittadini di paesi terzi di cui all’articolo 6 <span class=\"italics\">bis</span>, paragrafo 3, lettere a), b) e f), all’articolo 6 <span class=\"italics\">bis</span>, paragrafo 3, lettera g), punti i), ii), iii) e vii) e all’articolo 6 <span class=\"italics\">bis</span>, paragrafo 3, lettera j).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Le disposizioni del presente regolamento relative ai dati di ingresso/uscita registrati nell’EES e all’assenza di tali dati nell’EES, in particolare l’articolo 8, paragrafo 3, lettera a), punto iii bis), e lettera g), punto iv), l’articolo 8 <span class=\"italics\">quinquies</span>, paragrafo 4, lettera d), e l’articolo 12, si applicano mutatis mutandis ai timbri d’ingresso e di uscita.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Qualora una presunzione in ordine al soddisfacimento delle condizioni relative alla durata del soggiorno di breve durata è confutata in conformità dell’articolo 12, paragrafo 2, il cittadino di paese terzo presente nel territorio di uno Stato membro in cui l’EES non è ancora operativo ha diritto ad ottenere l’inserimento, nel suo documento di viaggio, di un’indicazione in merito alla data e al luogo in cui ha attraversato la frontiera esterna o interna di tale Stato membro. Al cittadino di paese terzo si potrà inoltre fornire il modulo figurante nell’allegato VIII.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Si applicano le disposizioni sull’apposizione di timbri di cui all’allegato IV.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Gli Stati membri di cui all’articolo 66, paragrafo 3, del regolamento (UE) 2017/2226 appongono timbri sui documenti di viaggio dei cittadini di paesi terzi il cui ingresso per un soggiorno di breve durata è stato rifiutato presso la loro frontiera. L’apposizione di timbri è eseguita conformemente alle specifiche contenute nell’allegato V, parte A, punto 1, lettera d).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Gli obblighi di apposizione del timbro ai sensi dei paragrafi da 1 a 6 si applicano fino alla data di entrata in funzione dell’l’EES nello Stato membro in questione.</div>\n</div>"]]}, "42b": {"label": "Articolo 42 ter", "heading": "Notifica delle regioni transfrontaliere", "anchor": "art_42b", "frags": [[null, "<p class=\"norm\">Entro l'11 gennaio 2025, tutti gli Stati membri con frontiere interne comuni determinano, in stretta cooperazione, le zone del loro territorio che considerano regioni transfrontaliere, tenuto conto dei forti legami sociali ed economici che le uniscono, e ne danno notifica alla Commissione.</p>"], [null, "<p class=\"norm\">Gli Stati membri comunicano alla Commissione ogni successiva modifica.</p>"]]}, "43": {"label": "Articolo 43", "heading": "Meccanismo di valutazione", "anchor": "art_43", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Conformemente ai trattati e fatte salve le disposizioni ivi contenute in materia di procedure d'infrazione, l'attuazione del presente regolamento da parte di ciascuno Stato membro è valutata mediante un meccanismo di valutazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le norme applicabili al meccanismo di valutazione sono definite nel regolamento (UE) n. 1053/2013. Conformemente a tale meccanismo di valutazione, gli Stati membri e la Commissione effettuano congiuntamente valutazioni periodiche, oggettive e imparziali al fine di verificare la corretta applicazione del presente regolamento e la Commissione deve coordinare la valutazione in stretta cooperazione con gli Stati membri. In base a tale meccanismo, ciascuno Stato membro è valutato almeno ogni cinque anni da una piccola squadra composta di rappresentanti della Commissione e di esperti designati dagli Stati membri.</div>\n</div>"], [null, "<p class=\"norm\">Le valutazioni possono consistere in visite in loco con o senza preavviso alle frontiere esterne o interne.</p>"], [null, "<p class=\"norm\">In base a tale meccanismo di valutazione, la Commissione è responsabile dell'adozione dei programmi di valutazione annuali e pluriennali e delle relazioni di valutazione.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">In caso di eventuali carenze, raccomandazioni sui provvedimenti correttivi possono essere indirizzate agli Stati membri.</div>\n</div>"], [null, "<p class=\"norm\">Qualora una relazione di valutazione adottata dalla Commissione ai sensi dell'articolo 14 del regolamento (UE) n. 1053/2013 individui gravi carenze nello svolgimento del controllo alle frontiere esterne, si applicano gli articoli 21 e 29 del presente regolamento.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Il Parlamento europeo e il Consiglio sono informati in tutte le fasi della valutazione e tutti i documenti pertinenti sono loro trasmessi conformemente alle norme applicabili ai documenti classificati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Il Parlamento europeo è informato immediatamente ed esaurientemente di eventuali proposte intese a modificare le norme di cui al regolamento (UE) n. 1053/2013.</div>\n</div>"]]}, "44": {"label": "Articolo 44", "heading": "Abrogazione", "anchor": "art_44", "frags": [[null, "<p class=\"norm\">Il regolamento (CE) n. 562/2006 è abrogato.</p>"], [null, "<p class=\"norm\">I riferimenti al regolamento abrogato si intendono fatti al presente regolamento e si leggono secondo la tavola di concordanza di cui all’allegato X.</p>"]]}, "45": {"label": "Articolo 45", "heading": "Entrata in vigore", "anchor": "art_45", "frags": [[null, "<p class=\"norm\">Il presente regolamento entra in vigore il ventesimo giorno successivo alla pubblicazione nella <span class=\"italics\">Gazzetta ufficiale dell'Unione europea</span>.</p>"]]}}, "recitals": {}};